import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
}

export interface UserProfile {
  name: string;
  joinedAt: Date;
}

import { GoogleGenAI, Chat } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export class GeminiService {
  private ai: GoogleGenAI;
  private chatSession: any = null;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  initChat(userName: string) {
    const systemInstruction = `You are IETE Bot, the official AI assistant for The Institution of Electronics and Telecommunication Engineers (IETE) India. 
    You are an expert in Electronics, Telecommunications, IT, and Engineering Education. 
    Your personality: Professional, academic, helpful, and technically proficient.
    Guidelines:
    1. Always address the user by their name: ${userName}.
    2. Provide accurate technical information.
    3. If asked about IETE, highlight its role in advancing science and technology in electronics.
    4. Keep greetings warm but formal.
    5. Use Markdown for formatting code, lists, and emphasis.`;

    this.chatSession = this.ai.chats.create({
      model: MODEL_NAME,
      config: {
        systemInstruction,
        temperature: 0.7,
        topP: 0.8,
        topK: 40,
      },
    });
    return this.chatSession;
  }

  async *sendMessageStream(message: string) {
    if (!this.chatSession) {
      throw new Error("Chat session not initialized");
    }

    const result = await this.chatSession.sendMessageStream({ message });
    for await (const chunk of result) {
      yield chunk.text || "";
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Onboarding from './components/Onboarding';
import ChatInterface from './components/ChatInterface';
import { UserProfile } from './types';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);

  useEffect(() => {
    const savedUser = localStorage.getItem('iete_user');
    if (savedUser) {
      try {
        const parsed = JSON.parse(savedUser);
        setUser({
          ...parsed,
          joinedAt: new Date(parsed.joinedAt)
        });
      } catch (e) {
        console.error("Failed to load user session", e);
      }
    }
  }, []);

  const handleStart = (name: string) => {
    const newUser: UserProfile = {
      name,
      joinedAt: new Date()
    };
    setUser(newUser);
    localStorage.setItem('iete_user', JSON.stringify(newUser));
  };

  const handleReset = () => {
    localStorage.removeItem('iete_user');
    setUser(null);
  };

  return (
    <div className="flex flex-col min-h-screen bg-slate-50">
      <Header onReset={handleReset} showReset={!!user} />

      <main className="flex-1 flex flex-col max-w-5xl w-full mx-auto p-4 md:p-6">
        {!user ? (
          <Onboarding onStart={handleStart} />
        ) : (
          <ChatInterface user={user} />
        )}
      </main>

      <footer className="py-4 text-center text-xs text-slate-400 border-t border-slate-200 bg-white">
        © {new Date().getFullYear()} The Institution of Electronics and Telecommunication Engineers. Powered by Gemini.
      </footer>
    </div>
  );
};

export default App;

