import { GoogleGenAI } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export class GeminiService {
  private ai: GoogleGenAI;
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  initChat(userName: string) {
    this.systemInstruction = `You are IETE Bot, the official AI assistant for The Institution of Electronics and Telecommunication Engineers (IETE) India. 
    You are an expert in Electronics, Telecommunications, IT, and Engineering Education. 

    CAPABILITIES:
    1. IMAGE ANALYSIS: You can see and analyze circuit diagrams, PCB layouts, and technical hardware photos.
    2. OCR: Extract text from any uploaded engineering documents or labels.
    3. WEB SEARCH: Use the googleSearch tool to find related technical images, datasheets, or recent engineering news.

    GUIDELINES:
    - Always address the user as ${userName}.
    - If an image is provided, first describe what you see from a technical perspective.
    - If text is extracted, analyze it for engineering relevance.
    - Provide related links or mention where users can find more images/datasheets using search grounding.
    - Use Markdown for code blocks and bold emphasis.`;

    this.history = [];
  }

  async *sendMessageStream(message: string, imageData?: { data: string; mimeType: string }) {
    const userParts: any[] = [{ text: message }];

    if (imageData) {
      userParts.push({
        inlineData: {
          data: imageData.data,
          mimeType: imageData.mimeType
        }
      });
    }

    // Prepare the contents including history
    const contents = [
      ...this.history,
      { role: 'user', parts: userParts }
    ];

    const result = await this.ai.models.generateContentStream({
      model: MODEL_NAME,
      contents,
      config: {
        systemInstruction: this.systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    });

    let fullText = "";
    for await (const chunk of result) {
      const text = chunk.text || "";
      fullText += text;
      yield text;
    }

    // Update history after completion
    this.history.push({ role: 'user', parts: userParts });
    this.history.push({ role: 'model', parts: [{ text: fullText }] });
  }
}

