import { GoogleGenAI } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export interface GroundingSource {
  title: string;
  uri: string;
}

export class GeminiService {
  private ai: GoogleGenAI;
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  initChat(userName: string) {
    this.systemInstruction = `You are IETE Bot, the official AI assistant for The Institution of Electronics and Telecommunication Engineers (IETE) India. 
    You are an expert in Electronics, Telecommunications, IT, and Engineering Education. 

    CAPABILITIES:
    1. IMAGE ANALYSIS: Analyze circuit diagrams, PCB layouts, and technical hardware photos.
    2. OCR: Extract and explain text from uploaded engineering documents.
    3. VISUAL SEARCH: When asked to fetch related images, use the googleSearch tool to find technical diagrams, datasheets, or institutional photos on the web.

    GUIDELINES:
    - Always address the user as ${userName}.
    - When searching for images, provide a descriptive summary of what the images represent and list the source URLs clearly.
    - Use Markdown for formatting.
    - If Google Search is used, ensure the user knows these are external professional resources.`;

    this.history = [];
  }

  async sendMessageStream(message: string, imageData?: { data: string; mimeType: string }) {
    const userParts: any[] = [{ text: message }];

    if (imageData) {
      userParts.push({
        inlineData: {
          data: imageData.data,
          mimeType: imageData.mimeType
        }
      });
    }

    const contents = [
      ...this.history,
      { role: 'user', parts: userParts }
    ];

    const response = await this.ai.models.generateContentStream({
      model: MODEL_NAME,
      contents,
      config: {
        systemInstruction: this.systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.7,
      },
    });

    return response;
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
  }
}

