import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps {
  user: UserProfile;
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedImage, setSelectedImage] = useState<{ data: string; mimeType: string } | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const hours = new Date().getHours();
    let greeting = 'Hello';
    if (hours < 12) greeting = 'Good Morning';
    else if (hours < 17) greeting = 'Good Afternoon';
    else greeting = 'Good Evening';

    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `${greeting}, ${user.name}! I am IETE Bot. I can analyze your technical images or search the web for related engineering visuals. \n\nHow can I assist you today?`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setSelectedImage({
          data: base64String,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleFetchVisuals = () => {
    if (isLoading) return;
    const lastUserMsg = [...messages].reverse().find(m => m.role === 'user')?.content || "IETE engineering";
    const visualPrompt = `Search for and fetch related professional engineering images, circuit diagrams, or technical visuals related to: "${lastUserMsg}". Provide descriptions and links.`;
    processMessage(visualPrompt);
  };

  const processMessage = async (text: string, img?: { data: string; mimeType: string }) => {
    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: img || undefined
    };

    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMessage]);

    try {
      let fullContent = '';
      let sources: { title: string; uri: string }[] = [];
      const streamResponse = await geminiService.sendMessageStream(text, img);

      for await (const chunk of streamResponse) {
        fullContent += chunk.text || "";

        // Extract grounding sources if they exist in any chunk
        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
          groundingChunks.forEach((c: any) => {
            if (c.web && !sources.find(s => s.uri === c.web.uri)) {
              sources.push({ title: c.web.title, uri: c.web.uri });
            }
          });
        }

        setMessages(prev => prev.map(msg => 
          msg.id === assistantMessageId ? { ...msg, content: fullContent, sources: sources.length > 0 ? sources : undefined } : msg
        ));
      }

      geminiService.updateHistory('user', [{ text: text }, ...(img ? [{ inlineData: img }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);

    } catch (error: any) {
      console.error("Chat error:", error);
      let errorDisplay = "Neural link interrupted.";

      if (error.message?.includes('RATE_LIMIT')) {
        errorDisplay = "Neural cores are overloaded (Rate Limit reached). Please pause for 60 seconds and retry your command.";
      } else if (error.message?.includes('OFFLINE')) {
        errorDisplay = "IETE Link severed. Please check your network connection and try again.";
      } else {
        errorDisplay = "A processing exception occurred in the Gemini matrix. Please try re-sending your command.";
      }

      setMessages(prev => prev.map(msg => 
        msg.id === assistantMessageId 
          ? { ...msg, content: errorDisplay } 
          : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedImage) || isLoading) return;

    const currentInput = input;
    const currentImage = selectedImage;

    setInput('');
    setSelectedImage(null);
    processMessage(currentInput || (currentImage ? "Analyze this technical image." : ""), currentImage || undefined);
  };

  return (
    <div className="flex-1 flex flex-col dark-glass-card rounded-[2rem] shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700 h-[calc(100vh-220px)] relative border border-white/5">
      <div className="scan-line"></div>
      <div className="h-1 bg-gradient-to-r from-transparent via-blue-500 to-transparent opacity-50 relative z-10"></div>

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar chat-blueprint"
      >
        <div className="watermark-overlay" style={{ backgroundImage: `url(${BOT_LOGO})`, filter: 'none', opacity: 0.03 }}></div>

        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex relative z-10 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div className={`max-w-[90%] md:max-w-[80%] flex gap-3.5 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-9 h-9 rounded-xl flex-shrink-0 flex items-center justify-center text-[11px] font-black shadow-lg overflow-hidden border ${
                msg.role === 'user' 
                  ? 'bg-blue-600/10 text-blue-400 border-blue-500/30' 
                  : 'bg-white border-white/10'
              }`}>
                {msg.role === 'user' ? user.name[0].toUpperCase() : (
                  <img src={BOT_LOGO} className="w-full h-full object-contain" alt="Bot avatar" />
                )}
              </div>
              <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                {msg.image && (
                  <div className="rounded-2xl overflow-hidden border border-white/20 shadow-2xl max-w-sm mb-1 group relative">
                    <img 
                      src={`data:${msg.image.mimeType};base64,${msg.image.data}`} 
                      alt="User uploaded" 
                      className="w-full h-auto object-cover max-h-64"
                    />
                    <div className="absolute inset-0 bg-blue-600/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                  </div>
                )}
                <div className={`rounded-2xl px-5 py-3.5 shadow-xl ${
                  msg.role === 'user' 
                    ? 'bg-gradient-to-br from-blue-600 to-blue-800 text-white rounded-tr-none user-bubble-glow' 
                    : 'bg-white/95 backdrop-blur-md text-slate-900 rounded-tl-none border border-white/50 ring-1 ring-black/5'
                }`}>
                  <div className={`whitespace-pre-wrap text-[14px] leading-relaxed tracking-tight ${msg.role === 'assistant' ? 'font-medium' : 'font-normal'}`}>
                    {msg.content || (isLoading && msg.id === messages[messages.length - 1].id ? (
                      <div className="flex flex-col gap-1.5">
                        <span className="flex gap-2 py-1">
                          <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                          <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                          <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce"></span>
                        </span>
                        <span className="text-[10px] text-blue-600/60 font-black uppercase tracking-widest animate-pulse">
                          IETE Bot is typing...
                        </span>
                      </div>
                    ) : '')}
                  </div>

                  {msg.sources && (
                    <div className="mt-4 pt-3 border-t border-slate-200">
                      <p className="text-[9px] font-bold text-blue-600 uppercase tracking-widest mb-2 flex items-center gap-1.5">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M12.586 4.586a2 2 0 112.828 2.828l-3 3a2 2 0 01-2.828 0 1 1 0 00-1.414 1.414 4 4 0 005.656 0l3-3a4 4 0 00-5.656-5.656l-1.5 1.5a1 1 0 101.414 1.414l1.5-1.5zm-5 5a2 2 0 012.828 0 1 1 0 101.414-1.414 4 4 0 00-5.656 0l-3 3a4 4 0 005.656 5.656l1.5-1.5a1 1 0 10-1.414-1.414l-1.5 1.5a2 2 0 11-2.828-2.828l3-3z" clipRule="evenodd" />
                        </svg>
                        Technical Resources Found
                      </p>
                      <div className="flex flex-wrap gap-2">
                        {msg.sources.map((s, idx) => (
                          <a 
                            key={idx} 
                            href={s.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="text-[10px] bg-blue-50 text-blue-700 px-2 py-1 rounded-md border border-blue-100 hover:bg-blue-100 transition-colors truncate max-w-[180px]"
                            title={s.title}
                          >
                            {s.title || "External Source"}
                          </a>
                        ))}
                      </div>
                    </div>
                  )}

                  <div className={`text-[8px] mt-2.5 font-black uppercase tracking-[0.15em] opacity-40 ${msg.role === 'user' ? 'text-blue-100 text-right' : 'text-slate-500'}`}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Input Section */}
      <form onSubmit={handleSend} className="p-4 md:p-6 border-t border-white/10 bg-slate-950/90 backdrop-blur-2xl relative z-10">

        {selectedImage && (
          <div className="max-w-4xl mx-auto mb-4 animate-in slide-in-from-bottom-2 duration-300">
            <div className="relative inline-block group">
              <img 
                src={`data:${selectedImage.mimeType};base64,${selectedImage.data}`} 
                className="h-20 w-auto rounded-xl border-2 border-blue-500 shadow-lg"
                alt="Selected preview"
              />
              <button 
                type="button"
                onClick={() => setSelectedImage(null)}
                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg hover:bg-red-600 transition-colors"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                </svg>
              </button>
            </div>
          </div>
        )}

        <div className="flex gap-2.5 relative max-w-4xl mx-auto items-center">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept="image/*" 
            className="hidden" 
          />

          <button
            type="button"
            onClick={() => fileInputRef.current?.click()}
            title="Attach Technical Image"
            className="p-3.5 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400 hover:border-blue-500/50 transition-all shadow-inner group"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          </button>

          <button
            type="button"
            onClick={handleFetchVisuals}
            title="Fetch Related Visuals"
            className="p-3.5 bg-blue-600/10 border border-blue-500/20 rounded-2xl text-blue-400 hover:bg-blue-600/20 hover:border-blue-500 transition-all shadow-inner group"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 group-hover:rotate-12 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0zM10 7v3m0 0v3m0-3h3m-3 0H7" />
            </svg>
          </button>

          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={selectedImage ? "Explain this visual..." : "Query IETE intelligence..."}
            disabled={isLoading}
            className="flex-1 px-5 py-4 rounded-2xl bg-white/5 border border-white/10 text-white focus:ring-2 focus:ring-blue-500 focus:bg-white/10 outline-none transition-all disabled:opacity-50 placeholder:text-slate-700 shadow-inner text-sm font-medium"
          />

          <button
            type="submit"
            disabled={isLoading || (!input.trim() && !selectedImage)}
            className="px-8 py-4 bg-gradient-to-br from-blue-600 to-blue-800 hover:from-blue-500 hover:to-blue-700 text-white font-black rounded-2xl shadow-lg shadow-blue-900/40 transition-all active:scale-95 disabled:opacity-30 disabled:grayscale flex items-center justify-center uppercase tracking-[0.2em] text-[10px]"
          >
            {isLoading ? (
              <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : 'Command'}
          </button>
        </div>
      </form>
    </div>
  );
};

