        videoRef.current.srcObject = stream;
        videoRef.current.play();
      }
      setIsCameraOpen(true);
    } catch (err) {
      alert("Failed to access optical sensors (camera). Please check permissions.");
    }
  };

  const closeCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        const base64 = dataUrl.split(',')[1];
        setSelectedImage({ data: base64, mimeType: 'image/jpeg' });
        closeCamera();
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setSelectedImage({ data: base64String, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAction = (type: 'extract' | 'solve' | 'search') => {
    if (isLoading) return;

    let prompt = "";
    const lastUserMsg = [...messages].reverse().find(m => m.role === 'user')?.content || "";

    if (type === 'extract') {
      prompt = `EXTRACT COMMAND: Please extract all text, part numbers, and technical specifications from this image accurately. List them in a structured format.`;
    } else if (type === 'solve') {
      prompt = `SOLVE COMMAND: Provide a step-by-step analytical solution for the engineering problem shown. If no problem is visible, solve for: "${lastUserMsg || 'General Engineering Inquiry'}".`;
    } else if (type === 'search') {
      prompt = `SEARCH COMMAND: Search the web for related technical images, diagrams, and datasheets for: "${lastUserMsg || 'IETE technical documentation'}".`;
    }

    processMessage(prompt, selectedImage || undefined);
    setSelectedImage(null);
  };

  const processMessage = async (text: string, img?: { data: string; mimeType: string }) => {
    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: img || undefined
    };

    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMessage]);

    try {
      let fullContent = '';
      let sources: { title: string; uri: string }[] = [];
      const streamResponse = await geminiService.sendMessageStream(text, img);

      for await (const chunk of streamResponse) {
        fullContent += chunk.text || "";
        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
          groundingChunks.forEach((c: any) => {
            if (c.web && !sources.find(s => s.uri === c.web.uri)) {
              sources.push({ title: c.web.title, uri: c.web.uri });
            }
          });
        }
        setMessages(prev => prev.map(msg => 
          msg.id === assistantMessageId ? { ...msg, content: fullContent, sources: sources.length > 0 ? sources : undefined } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text: text }, ...(img ? [{ inlineData: img }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map(msg => 
        msg.id === assistantMessageId ? { ...msg, content: error.message || "Neural failure." } : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedImage) || isLoading) return;
    const txt = input;
    const img = selectedImage;
    setInput('');
    setSelectedImage(null);
    processMessage(txt || (img ? "Analyze this image." : ""), img || undefined);
