          <div key={msg.id} className={`flex relative z-10 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[90%] md:max-w-[80%] flex gap-3.5 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-9 h-9 rounded-xl flex-shrink-0 flex items-center justify-center shadow-lg overflow-hidden border bg-white">
                {msg.role === 'user' ? (
                  <div className="w-full h-full bg-blue-600 flex items-center justify-center text-white font-bold text-xs">{user.name[0]}</div>
                ) : <img src={BOT_LOGO} className="w-full h-full object-contain" alt="Bot" />}
              </div>
              <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                {msg.image && (
                  <div className="rounded-2xl overflow-hidden border border-white/20 shadow-2xl max-w-sm">
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-64 object-cover" alt="Uploaded" />
                  </div>
                )}
                <div className={`rounded-2xl px-5 py-3.5 shadow-xl ${
                  msg.role === 'user' ? 'bg-blue-700 text-white rounded-tr-none' : 'bg-white text-slate-900 rounded-tl-none border'
                }`}>
                  <div className="whitespace-pre-wrap text-[14px] leading-relaxed">
                    {msg.content || (isLoading && msg.id === messages[messages.length - 1].id ? "Processing..." : "")}
                  </div>
                  {msg.sources && (
                    <div className="mt-3 pt-3 border-t border-slate-200 flex flex-wrap gap-2">
                      {msg.sources.map((s, i) => (
                        <a key={i} href={s.uri} target="_blank" className="text-[10px] bg-blue-50 text-blue-700 px-2 py-1 rounded border">{s.title || "Source"}</a>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Toolkit & Input */}
      <div className="p-4 md:p-6 bg-slate-950/90 backdrop-blur-2xl border-t border-white/10 z-20">

        {/* Camera Modal */}
        {isCameraOpen && (
          <div className="fixed inset-0 z-50 bg-black flex flex-col">
            <video ref={videoRef} className="flex-1 object-cover" autoPlay playsInline />
            <div className="p-8 flex justify-between items-center bg-black/80">
              <button onClick={closeCamera} className="text-white uppercase font-bold text-xs tracking-widest">Abort</button>
              <button onClick={capturePhoto} className="w-16 h-16 rounded-full border-4 border-white flex items-center justify-center p-1">
                <div className="w-full h-full bg-white rounded-full"></div>
              </button>
              <div className="w-12"></div>
            </div>
            <canvas ref={canvasRef} className="hidden" />
          </div>
        )}

        {/* Selected Image Preview */}
        {selectedImage && (
          <div className="flex items-center gap-3 mb-4 animate-in slide-in-from-bottom-2">
            <div className="relative group">
              <img src={`data:${selectedImage.mimeType};base64,${selectedImage.data}`} className="h-16 w-16 object-cover rounded-xl border-2 border-blue-500" alt="Preview" />
              <button onClick={() => setSelectedImage(null)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg">✕</button>
            </div>
            <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">Image Loaded</p>
          </div>
        )}

        {/* Toolkit Toolbar */}
        <div className="flex gap-2 mb-4 overflow-x-auto pb-2 custom-scrollbar">
          <button 
            onClick={() => handleAction('extract')}
            className="whitespace-nowrap px-4 py-2 bg-blue-600/10 border border-blue-500/30 rounded-xl text-blue-400 text-[10px] font-black uppercase tracking-widest hover:bg-blue-600/20 transition-all"
          >
