          >
            Fetch Visuals
          </button>
        </div>

        {/* Main Input Bar */}
        <form onSubmit={handleSend} className="flex gap-2.5 max-w-4xl mx-auto items-center">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />

          <div className="flex gap-1.5">
            <button type="button" onClick={openCamera} className="p-3.5 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
              </svg>
            </button>
            <button type="button" onClick={() => fileInputRef.current?.click()} className="p-3.5 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
              </svg>
            </button>
          </div>

          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Query IETE Bot..."
            disabled={isLoading}
            className="flex-1 px-5 py-4 rounded-2xl bg-white/5 border border-white/10 text-white focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-50 text-sm font-medium"
          />

          <button
            type="submit"
            disabled={isLoading || (!input.trim() && !selectedImage)}
            className="px-8 py-4 bg-gradient-to-br from-blue-600 to-blue-800 text-white font-black rounded-2xl uppercase tracking-[0.2em] text-[10px] shadow-lg shadow-blue-900/40"
          >
            {isLoading ? <div className="w-4 h-4 border-2 border-t-white rounded-full animate-spin" /> : 'Run'}
          </button>
        </form>
      </div>
    </div>
  );
};

