{
  "name": "IETE Bot",
  "description": "The official professional AI assistant for The Institution of Electronics and Telecommunication Engineers, providing technical guidance and institutional information.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import { GoogleGenAI } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export interface GroundingSource {
  title: string;
  uri: string;
}

export class GeminiService {
  private ai: GoogleGenAI;
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  initChat(userName: string) {
    this.systemInstruction = `You are IETE Bot, the official AI assistant for The Institution of Electronics and Telecommunication Engineers (IETE) India. 
    You are an expert in Electronics, Telecommunications, IT, and Engineering Education. 

    MODES OF OPERATION:
    1. ANALYZE/SOLVE: Provide rigorous step-by-step analytical solutions for engineering problems (circuits, math, logic).
    2. EXTRACT TEXT: Perform high-precision OCR on technical docs or component labels.
    3. VISUAL SEARCH: Use the googleSearch tool to find technical diagrams, datasheets, or institutional photos.
    4. IDENTIFY SOUND: Analyze audio inputs to identify soundtracks, technical noises (like capacitor whine or motor humming), or verbal commands.
    5. DEBUG CIRCUIT: Analyze circuit photos to find potential shorts, missing components, or layout errors.
    6. EXPLAIN LOGIC: Explain complex code, truth tables, or communication protocols.

    GUIDELINES:
    - Address the user as ${userName}.
    - Be precise and professional. Use Markdown and LaTeX for technical content.
    - When identifying audio, describe the characteristics (frequency, rhythm, likely source) if specific metadata isn't available.`;

    this.history = [];
  }

  async sendMessageStream(message: string, mediaData?: { data: string; mimeType: string }) {
    const userParts: any[] = [{ text: message }];

    if (mediaData) {
      userParts.push({
        inlineData: {
          data: mediaData.data,
          mimeType: mediaData.mimeType
        }
      });
    }

    const contents = [
      ...this.history,
      { role: 'user', parts: userParts }
    ];

    try {
      const response = await this.ai.models.generateContentStream({
        model: MODEL_NAME,
        contents,
        config: {
          systemInstruction: this.systemInstruction,
          tools: [{ googleSearch: {} }],
          temperature: 0.7,
        },
      });
      return response;
    } catch (error: any) {
      console.error("Gemini API error:", error);
      if (error.message?.includes('429')) {
        throw new Error("RATE_LIMIT: Neural cores overloaded. Cool down for 60s.");
      } else if (!navigator.onLine) {
        throw new Error("OFFLINE: IETE link severed. Check internet.");
      }
      throw new Error("GENERAL_ERROR: Processing fault in the Gemini matrix.");
    }
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
  }
}

export const geminiService = new GeminiService();

