                      <div className="flex items-center gap-2 py-2">
                        <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce"></div>
                        <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                        <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                        <span className="text-[10px] uppercase font-bold text-blue-500 opacity-60">IETE bot is computing...</span>
                      </div>
                    ) : "")}
                  </div>
                  {msg.sources && (
                    <div className="mt-3 pt-3 border-t border-slate-200 flex flex-wrap gap-2">
                      {msg.sources.map((s, i) => (
                        <a key={i} href={s.uri} target="_blank" className="text-[10px] bg-blue-50 text-blue-700 px-2 py-1 rounded border">{s.title || "Source"}</a>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="p-4 md:p-6 bg-slate-950/90 backdrop-blur-2xl border-t border-white/10 z-20">

        {isCameraOpen && (
          <div className="fixed inset-0 z-50 bg-black flex flex-col">
            <video ref={videoRef} className="flex-1 object-cover" autoPlay playsInline />
            <div className="p-8 flex justify-between items-center bg-black/80">
              <button onClick={closeCamera} className="text-white uppercase font-bold text-xs">Abort</button>
              <button onClick={capturePhoto} className="w-16 h-16 rounded-full border-4 border-white p-1"><div className="w-full h-full bg-white rounded-full"></div></button>
              <div className="w-12"></div>
            </div>
            <canvas ref={canvasRef} className="hidden" />
          </div>
        )}

        {selectedMedia && (
          <div className="flex items-center gap-3 mb-4 animate-in slide-in-from-bottom-2">
            <div className="relative group">
              {selectedMedia.mimeType.startsWith('image/') ? (
                <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-16 w-16 object-cover rounded-xl border-2 border-blue-500" alt="Preview" />
              ) : (
                <div className="h-16 w-16 bg-blue-900/30 flex items-center justify-center rounded-xl border-2 border-blue-500">
                  <svg className="h-8 w-8 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" /></svg>
                </div>
              )}
              <button onClick={() => setSelectedMedia(null)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg">✕</button>
            </div>
            <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">{selectedMedia.mimeType.split('/')[0]} Data Loaded</p>
          </div>
        )}

        <div className="flex gap-2 mb-4 overflow-x-auto pb-2 custom-scrollbar">
          {[
            { id: 'extract', label: 'Extract Text', color: 'blue' },
            { id: 'solve', label: 'Solve Problem', color: 'indigo' },
            { id: 'audio', label: 'Identify Sound', color: 'purple' },
            { id: 'debug', label: 'Debug Circuit', color: 'red' },
            { id: 'code', label: 'Logic Analysis', color: 'orange' },
            { id: 'search', label: 'Fetch Visuals', color: 'emerald' },
          ].map(btn => (
            <button 
              key={btn.id}
              onClick={() => handleAction(btn.id as any)}
              className={`whitespace-nowrap px-4 py-2 bg-${btn.color}-600/10 border border-${btn.color}-500/30 rounded-xl text-${btn.color}-400 text-[10px] font-black uppercase tracking-widest hover:bg-${btn.color}-600/20 transition-all`}
            >
              {btn.label}
            </button>
          ))}
        </div>

        <form onSubmit={handleSend} className="flex gap-2.5 max-w-4xl mx-auto items-center">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*,audio/*" className="hidden" />

          <div className="flex gap-1.5">
            <button type="button" onClick={openCamera} className="p-3.5 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400 transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
            </button>
            <button 
              type="button" 
              onMouseDown={startRecording}
              onMouseUp={stopRecording}
              onTouchStart={startRecording}
              onTouchEnd={stopRecording}
              className={`p-3.5 border rounded-2xl transition-all ${isRecording ? 'bg-red-500/20 border-red-500 text-red-500 animate-pulse' : 'bg-white/5 border-white/10 text-slate-400 hover:text-purple-400'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
            </button>
            <button type="button" onClick={() => fileInputRef.current?.click()} className="p-3.5 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400 transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
            </button>
          </div>

          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={isRecording ? "Listening to soundtrack..." : "Query IETE Bot..."}
            disabled={isLoading || isRecording}
            className="flex-1 px-5 py-4 rounded-2xl bg-white/5 border border-white/10 text-white focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-50 text-sm font-medium"
          />

          <button
            type="submit"
            disabled={isLoading || (!input.trim() && !selectedMedia) || isRecording}
            className="px-8 py-4 bg-gradient-to-br from-blue-600 to-blue-800 text-white font-black rounded-2xl uppercase tracking-[0.2em] text-[10px] shadow-lg shadow-blue-900/40"
          >
            {isLoading ? <div className="w-4 h-4 border-2 border-t-white rounded-full animate-spin" /> : 'Run'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatInterface;

import { GoogleGenAI } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export interface GroundingSource {
  title: string;
  uri: string;
}

export class GeminiService {
  private ai: GoogleGenAI;
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  initChat(userName: string) {
    this.systemInstruction = `You are IETE Bot, the premier AI engineer for The Institution of Electronics and Telecommunication Engineers (IETE) India. 
    You excel in Electronics, Communications, and IT.

    CORE COMMAND PROTOCOLS:
    1. EXTRACT SPECS: Precision OCR for datasheets, component labels, and schematics.
    2. CIRCUIT DEBUG: Visual analysis of PCB/schematic photos to detect errors.
    3. MATH/LOGIC SOLVER: Rigorous step-by-step solutions for engineering problems.
    4. COMPONENT IDENTIFIER: Identify electronic parts (ICs, transistors, sensors) from photos.
    5. SOUNDTRACK IDENTIFIER: Analyze audio input to identify music, technical hums, or verbal instructions.
    6. PINOUT GUIDE: Provide pinout diagrams or descriptions for components.
    7. IETE KNOWLEDGE: Provide accurate facts about IETE history, membership, and centers.

    GUIDELINES:
    - Address the user as ${userName}.
    - Be technically accurate. Use Markdown and LaTeX where appropriate.
    - If Google Search is triggered via tools, synthesize the web data to provide specific engineering answers.
    - If audio is provided for "Soundtrack Identification", focus on metadata (artist, track) or technical frequency analysis.`;

    this.history = [];
  }

  async sendMessageStream(message: string, mediaData?: { data: string; mimeType: string }) {
    const userParts: any[] = [{ text: message }];

    if (mediaData) {
      userParts.push({
        inlineData: {
          data: mediaData.data,
          mimeType: mediaData.mimeType
        }
      });
    }

    const contents = [
      ...this.history,
      { role: 'user', parts: userParts }
    ];

    try {
      console.log(`[IETE Bot] Initiating stream for: ${message.substring(0, 50)}...`);
      const response = await this.ai.models.generateContentStream({
        model: MODEL_NAME,
        contents,
        config: {
          systemInstruction: this.systemInstruction,
          tools: [{ googleSearch: {} }],
          temperature: 0.4, // Lower temperature for higher engineering precision
        },
      });
      return response;
    } catch (error: any) {
      console.error("[IETE Bot] API Error:", error);
      if (error.message?.includes('429')) {
        throw new Error("Neural cores throttled (Rate Limit). Please wait 60s.");
      } else if (!navigator.onLine) {
        throw new Error("Communication link lost. Check network.");
      }
      throw new Error(`Technical Fault: ${error.message || "Unknown processing error"}`);
    }
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps {
  user: UserProfile;
}

type ToolkitAction = 'extract' | 'solve' | 'search' | 'audio' | 'debug' | 'code' | 'component' | 'pinout' | 'iete';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const hours = new Date().getHours();
    let greeting = 'Hello';
    if (hours < 12) greeting = 'Good Morning';
    else if (hours < 17) greeting = 'Good Afternoon';
    else greeting = 'Good Evening';

    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `${greeting}, ${user.name}! I am IETE Bot. How can I support your engineering mission today?\n\nChoose a specialized tool from the matrix below or describe your query manually.`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  // Camera Logic
  const openCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        videoRef.current.play();
      }
      setIsCameraOpen(true);
    } catch (err) {
      alert("Sensor link failure (Camera access denied).");
    }
  };

  const closeCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      if (context) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        context.drawImage(videoRef.current, 0, 0);
        const dataUrl = canvasRef.current.toDataURL('image/jpeg');
        const base64 = dataUrl.split(',')[1];
        setSelectedMedia({ data: base64, mimeType: 'image/jpeg' });
        closeCamera();
      }
    }
  };

  // Audio Logic
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.onloadend = () => {
          const base64 = (reader.result as string).split(',')[1];
          setSelectedMedia({ data: base64, mimeType: 'audio/webm' });
        };
        reader.readAsDataURL(audioBlob);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      alert("Audio sensor blocked (Microphone access denied).");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setSelectedMedia({ data: base64String, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAction = async (type: ToolkitAction) => {
    if (isLoading) return;

    // Check if media is required for some actions
    const mediaRequired = ['extract', 'audio', 'debug', 'component'].includes(type);
    if (mediaRequired && !selectedMedia) {
      alert(`The ${type.toUpperCase()} tool requires image or audio data. Please upload or capture media first.`);
      return;
    }

    setActiveTool(type);

    let prompt = "";
    const lastUserMsg = [...messages].reverse().find(m => m.role === 'user')?.content || "";

    switch(type) {
      case 'extract': prompt = "COMMAND: EXTRACT SPECS. Perform high-precision OCR on this technical image."; break;
      case 'solve': prompt = "COMMAND: SOLVE PROBLEM. Provide a step-by-step technical solution for the visible problem."; break;
      case 'search': prompt = "COMMAND: VISUAL SEARCH. Find professional diagrams, schematics, or datasheets related to: " + (lastUserMsg || "IETE standards"); break;
      case 'audio': prompt = "COMMAND: IDENTIFY SOUNDTRACK. Analyze the provided audio to identify music, technical noise, or voice commands."; break;
      case 'debug': prompt = "COMMAND: DEBUG CIRCUIT. Analyze this circuit for faults, shorts, or missing components."; break;
      case 'code': prompt = "COMMAND: LOGIC ANALYSIS. Explain, debug, or optimize the algorithms/code provided."; break;
      case 'component': prompt = "COMMAND: IDENTIFY COMPONENT. Tell me what this electronic component is and its typical application."; break;
      case 'pinout': prompt = "COMMAND: PINOUT GUIDE. Provide the pinout and connection details for the component shown or mentioned."; break;
      case 'iete': prompt = "COMMAND: IETE FACTS. Provide detailed information about IETE centers, membership, or history."; break;
    }

    const currentMedia = selectedMedia;
    setSelectedMedia(null);
    await processMessage(prompt, currentMedia || undefined);
    setActiveTool(null);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading) return;

    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media?.mimeType.startsWith('image/') ? media : undefined
    };

    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMessage]);

    try {
      let fullContent = '';
      let sources: { title: string; uri: string }[] = [];
      const streamResponse = await geminiService.sendMessageStream(text, media);

      for await (const chunk of streamResponse) {
        fullContent += chunk.text || "";
        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
          groundingChunks.forEach((c: any) => {
            if (c.web && !sources.find(s => s.uri === c.web.uri)) {
              sources.push({ title: c.web.title, uri: c.web.uri });
            }
          });
        }
        setMessages(prev => prev.map(msg => 
          msg.id === assistantMessageId ? { ...msg, content: fullContent, sources: sources.length > 0 ? sources : undefined } : msg
        ));
      }

      geminiService.updateHistory('user', [{ text: text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);

    } catch (error: any) {
      console.error("[IETE Bot] Catching UI error:", error);
      setMessages(prev => prev.map(msg => 
        msg.id === assistantMessageId ? { ...msg, content: `Error: ${error.message || "Neural failure."}` } : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading) return;
    const txt = input;
    const med = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    processMessage(txt || (med ? "Analyze this data packet." : ""), med || undefined);
  };

  return (
    <div className="flex-1 flex flex-col dark-glass-card rounded-[2rem] shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700 h-[calc(100vh-220px)] relative border border-white/5">
      <div className="scan-line"></div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar chat-blueprint relative">
        <div className="watermark-overlay" style={{ backgroundImage: `url(${BOT_LOGO})`, opacity: 0.03 }}></div>
        {messages.map((msg) => (
          <div key={msg.id} className={`flex relative z-10 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[90%] md:max-w-[80%] flex gap-3.5 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-9 h-9 rounded-xl flex-shrink-0 flex items-center justify-center shadow-lg overflow-hidden border bg-white">
                {msg.role === 'user' ? (
                  <div className="w-full h-full bg-blue-600 flex items-center justify-center text-white font-bold text-xs">{user.name[0]}</div>
                ) : <img src={BOT_LOGO} className="w-full h-full object-contain" alt="Bot" />}
              </div>
              <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                {msg.image && (
                  <div className="rounded-2xl overflow-hidden border border-white/20 shadow-2xl max-w-sm">
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-64 object-cover" alt="Uploaded" />
                  </div>
                )}
                <div className={`rounded-2xl px-5 py-3.5 shadow-xl ${
                  msg.role === 'user' ? 'bg-blue-700 text-white rounded-tr-none' : 'bg-white text-slate-900 rounded-tl-none border'
                }`}>
                  <div className="whitespace-pre-wrap text-[14px] leading-relaxed">
                    {msg.content || (isLoading && msg.id === messages[messages.length - 1].id ? (
                      <div className="flex flex-col gap-2 py-2">
                        <div className="flex items-center gap-2">
                          <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce"></div>
                          <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                          <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                        </div>
                        <span className="text-[9px] uppercase font-black text-blue-500 tracking-widest opacity-80">
                          {activeTool ? `RUNNING ${activeTool.toUpperCase()} MODE...` : "IETE bot is computing..."}
                        </span>
                      </div>
                    ) : "")}
                  </div>
                  {msg.sources && (
                    <div className="mt-3 pt-3 border-t border-slate-200 flex flex-wrap gap-2">
                      {msg.sources.map((s, i) => (
                        <a key={i} href={s.uri} target="_blank" className="text-[10px] bg-blue-50 text-blue-700 px-2 py-1 rounded border hover:bg-blue-100 transition-colors">{s.title || "Source"}</a>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="p-4 md:p-6 bg-slate-950/90 backdrop-blur-2xl border-t border-white/10 z-20">

        {isCameraOpen && (
          <div className="fixed inset-0 z-50 bg-black flex flex-col">
            <video ref={videoRef} className="flex-1 object-cover" autoPlay playsInline />
            <div className="p-8 flex justify-between items-center bg-black/80">
              <button onClick={closeCamera} className="text-white uppercase font-bold text-xs">Abort</button>
              <button onClick={capturePhoto} className="w-16 h-16 rounded-full border-4 border-white p-1"><div className="w-full h-full bg-white rounded-full"></div></button>
              <div className="w-12"></div>
            </div>
            <canvas ref={canvasRef} className="hidden" />
          </div>
        )}

        {selectedMedia && (
          <div className="flex items-center gap-3 mb-4 animate-in slide-in-from-bottom-2">
            <div className="relative group">
              {selectedMedia.mimeType.startsWith('image/') ? (
                <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-16 w-16 object-cover rounded-xl border-2 border-blue-500" alt="Preview" />
              ) : (
                <div className="h-16 w-16 bg-blue-900/30 flex items-center justify-center rounded-xl border-2 border-blue-500">
                  <svg className="h-8 w-8 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" /></svg>
                </div>
              )}
              <button onClick={() => setSelectedMedia(null)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg">✕</button>
            </div>
            <div className="flex flex-col">
