            { id: 'solve', label: 'Solve Problem', color: 'indigo', icon: '🧠' },
            { id: 'soundtrack', label: 'Soundtrack ID', color: 'purple', icon: '🎵' },
            { id: 'debug', label: 'Circuit Debug', color: 'red', icon: '⚡' },
            { id: 'component', label: 'Identify Part', color: 'amber', icon: '🔍' },
            { id: 'pinout', label: 'Pinout Guide', color: 'pink', icon: '🔌' },
            { id: 'code', label: 'Logic Check', color: 'orange', icon: '💻' },
            { id: 'iete', label: 'IETE Facts', color: 'sky', icon: '🏛️' },
            { id: 'search', label: 'Find Diagrams', color: 'emerald', icon: '🖼️' },
          ].map(btn => (
            <button 
              key={btn.id}
              onClick={() => handleAction(btn.id as ToolkitAction)}
              disabled={isLoading}
              className={`flex items-center gap-2 whitespace-nowrap px-4 py-2.5 bg-${btn.color}-600/10 border border-${btn.color}-500/20 rounded-xl text-${btn.color}-400 text-[10px] font-bold uppercase tracking-widest hover:bg-${btn.color}-600/20 active:scale-95 transition-all disabled:opacity-30`}
            >
              <span>{btn.icon}</span>
              {btn.label}
            </button>
          ))}
        </div>

        {/* Message Input */}
        <form onSubmit={handleSend} className="flex gap-3 max-w-4xl mx-auto items-center">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*,audio/*,video/*" className="hidden" />

          <button 
            type="button" 
            onClick={() => fileInputRef.current?.click()} 
            disabled={isLoading} 
            className="p-4 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400 hover:bg-white/10 transition-all disabled:opacity-30 flex-shrink-0"
            title="Upload Image/Audio"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
            </svg>
          </button>

          <div className="flex-1 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask anything..."
              disabled={isLoading}
              className="w-full px-6 py-4 rounded-2xl bg-white/5 border border-white/10 text-white focus:ring-2 focus:ring-blue-500 focus:bg-white/10 outline-none disabled:opacity-50 text-sm font-medium transition-all"
            />
          </div>

          <button
            type="submit"
            disabled={isLoading || (!input.trim() && !selectedMedia)}
            className="px-8 py-4 bg-gradient-to-br from-blue-600 to-blue-800 text-white font-black rounded-2xl uppercase tracking-[0.2em] text-[10px] shadow-lg shadow-blue-900/40 transition-all hover:scale-[1.02] active:scale-95 disabled:opacity-30 flex-shrink-0"
          >
            {isLoading ? (
              <div className="w-5 h-5 border-2 border-t-white border-white/30 rounded-full animate-spin" />
            ) : (
              <div className="flex items-center gap-2">
                <span>Run</span>
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
                </svg>
              </div>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

