import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps {
  user: UserProfile;
}

type ToolkitAction = 'extract' | 'solve' | 'search' | 'debug' | 'code' | 'component' | 'pinout' | 'iete' | 'soundtrack';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const hours = new Date().getHours();
    let greeting = 'Hi';
    if (hours < 12) greeting = 'Good morning';
    else if (hours < 17) greeting = 'Good afternoon';
    else greeting = 'Good evening';

    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `${greeting} ${user.name}! I'm IETE Bot. I can extract text from images, solve math problems, identify soundtracks, and debug circuits. How can I help you today?`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setSelectedMedia({ data: base64String, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAction = async (type: ToolkitAction) => {
    if (isLoading) return;

    // Check for media requirements
    const mediaRequired = ['extract', 'debug', 'component', 'soundtrack'].includes(type);
    if (mediaRequired && !selectedMedia) {
      const mediaLabel = type === 'soundtrack' ? 'audio' : 'image';
      alert(`Please upload an ${mediaLabel} file first to use this toolkit feature.`);
      return;
    }

    setActiveTool(type);

    let prompt = "";
    const lastUserMsg = [...messages].reverse().find(m => m.role === 'user')?.content || "";

    switch(type) {
      case 'extract': prompt = "TOOLKIT COMMAND: EXTRACT TEXT. Precisely extract all text content from this uploaded image and format it clearly."; break;
      case 'solve': prompt = "TOOLKIT COMMAND: SOLVE. Provide a step-by-step technical solution for the visible problem in this image or the query mentioned."; break;
      case 'search': prompt = "TOOLKIT COMMAND: VISUAL SEARCH. Research and find technical diagrams or datasheets for: " + (lastUserMsg || "latest IETE technical standards"); break;
      case 'debug': prompt = "TOOLKIT COMMAND: DEBUG CIRCUIT. Analyze this hardware/circuit image for any obvious design errors or faults."; break;
      case 'code': prompt = "TOOLKIT COMMAND: LOGIC ANALYSIS. Analyze the logic of this code or technical flow and explain it simply."; break;
      case 'component': prompt = "TOOLKIT COMMAND: IDENTIFY PART. Identify this electronic component and describe its specs and usage."; break;
      case 'pinout': prompt = "TOOLKIT COMMAND: PINOUT. Show me the pinout and connection guide for this component."; break;
      case 'iete': prompt = "TOOLKIT COMMAND: IETE INFO. Tell me about IETE's history, professional membership benefits, or centers."; break;
      case 'soundtrack': prompt = "TOOLKIT COMMAND: SOUNDTRACK IDENTIFICATION. Identify the music, soundtrack, or acoustic signature in this audio file."; break;
    }

    const currentMedia = selectedMedia;
    setSelectedMedia(null);

    // Using a microtask to ensure tool state updates before heavy processing
    await new Promise(resolve => setTimeout(resolve, 0));
    await processMessage(prompt, currentMedia || undefined);
    setActiveTool(null);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading) return;

    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media?.mimeType.startsWith('image/') ? media : undefined
    };

    setMessages(prev => [...prev, userMessage]);
    setIsLoading(true);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMessage]);

    try {
      let fullContent = '';
      let sources: { title: string; uri: string }[] = [];
      const streamResponse = await geminiService.sendMessageStream(text, media);

      if (!streamResponse) throw new Error("No response from AI cores.");

      for await (const chunk of streamResponse) {
        const chunkText = chunk.text || "";
        fullContent += chunkText;

        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
          groundingChunks.forEach((c: any) => {
            if (c.web && !sources.find(s => s.uri === c.web.uri)) {
              sources.push({ title: c.web.title, uri: c.web.uri });
            }
          });
        }

        // Rapid UI update for fast typing feel
        setMessages(prev => prev.map(msg => 
          msg.id === assistantMessageId ? { ...msg, content: fullContent, sources: sources.length > 0 ? sources : undefined } : msg
        ));
      }

      geminiService.updateHistory('user', [{ text: text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);

    } catch (error: any) {
      console.error("[IETE Bot] Runtime Error:", error);
      setMessages(prev => prev.map(msg => 
        msg.id === assistantMessageId ? { 
          ...msg, 
          content: `⚠️ System Interrupted: ${error.message || "Connection timed out. Please try again."}` 
        } : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading) return;
    const txt = input;
    const med = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    processMessage(txt || (med ? "Process this file upload." : ""), med || undefined);
  };

  return (
    <div className="flex-1 flex flex-col dark-glass-card rounded-[2rem] shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700 h-[calc(100vh-220px)] relative border border-white/5">
      <div className="scan-line"></div>

      {/* Main Chat Viewport */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar chat-blueprint relative">
        <div className="watermark-overlay" style={{ backgroundImage: `url(${BOT_LOGO})`, opacity: 0.03 }}></div>
        {messages.map((msg, index) => {
          const isLatestAssistant = msg.role === 'assistant' && index === messages.length - 1;
          return (
            <div key={msg.id} className={`flex relative z-10 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] md:max-w-[80%] flex gap-3.5 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-10 h-10 rounded-xl flex-shrink-0 flex items-center justify-center shadow-lg overflow-hidden border ${msg.role === 'user' ? 'bg-blue-600 border-blue-500 shadow-blue-900/40' : 'bg-white border-white/20'}`}>
                  {msg.role === 'user' ? (
                    <span className="text-white font-black text-sm">{user.name[0]}</span>
                  ) : <img src={BOT_LOGO} className="w-full h-full object-contain p-1.5" alt="Bot" />}
                </div>
                <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  {msg.image && (
                    <div className="rounded-2xl overflow-hidden border border-white/20 shadow-2xl max-w-sm group relative">
                      <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-64 object-cover" alt="MediaContent" />
                    </div>
                  )}
                  <div className={`rounded-2xl px-6 py-4 shadow-xl relative transition-all duration-300 ${
                    msg.role === 'user' ? 'bg-blue-700 text-white rounded-tr-none user-bubble-glow' : 'bg-white text-slate-900 rounded-tl-none border border-slate-200'
                  }`}>
                    <div className="whitespace-pre-wrap text-[14px] leading-relaxed font-medium">
                      {msg.content}
                      {isLoading && isLatestAssistant && (
                        <span className="inline-block w-2 h-4 ml-1 bg-blue-500 animate-pulse align-middle" aria-hidden="true" />
                      )}
                    </div>
                    {msg.sources && (
                      <div className="mt-4 pt-3 border-t border-slate-100 flex flex-wrap gap-2">
                        {msg.sources.map((s, i) => (
                          <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[10px] bg-blue-50 text-blue-700 px-3 py-1.5 rounded-full border border-blue-100 hover:bg-blue-100 transition-colors font-bold uppercase tracking-wider">
                            {s.title || "Technical Source"}
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Control Station */}
      <div className="p-4 md:p-6 bg-slate-950/95 backdrop-blur-3xl border-t border-white/10 z-20">

        {/* Upload Hub Status */}
        {selectedMedia && (
          <div className="flex items-center gap-3 mb-5 animate-in slide-in-from-bottom-2 bg-blue-500/10 p-3 rounded-2xl border border-blue-500/30">
            <div className="relative group">
              {selectedMedia.mimeType.startsWith('image/') ? (
                <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-14 w-14 object-cover rounded-xl border-2 border-blue-500 shadow-lg shadow-blue-500/20" alt="Preview" />
              ) : (
                <div className="h-14 w-14 bg-blue-900/40 border-2 border-blue-500 rounded-xl flex items-center justify-center">
                  <svg className="w-7 h-7 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
                  </svg>
                </div>
              )}
              <button onClick={() => setSelectedMedia(null)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-6 h-6 flex items-center justify-center text-xs shadow-lg hover:bg-red-600 transition-colors border border-white/20">✕</button>
            </div>
            <div className="flex flex-col">
              <p className="text-[10px] text-blue-400 font-black uppercase tracking-widest">Media Uplink Ready</p>
              <p className="text-[9px] text-slate-400 font-medium">Select a Toolkit Mode or click Run</p>
            </div>
          </div>
        )}

        {/* Toolkit Matrix */}
        <div className="flex gap-2.5 mb-6 overflow-x-auto pb-3 custom-scrollbar no-scrollbar">
          {[
            { id: 'extract', label: 'Extract Text', color: 'blue', icon: '📄' },
            { id: 'solve', label: 'Solve Problem', color: 'indigo', icon: '🧠' },
            { id: 'soundtrack', label: 'Soundtrack ID', color: 'purple', icon: '🎵' },
            { id: 'debug', label: 'Circuit Debug', color: 'red', icon: '⚡' },
            { id: 'component', label: 'Identify Part', color: 'amber', icon: '🔍' },
            { id: 'pinout', label: 'Pinout Guide', color: 'pink', icon: '🔌' },
            { id: 'code', label: 'Logic Check', color: 'orange', icon: '💻' },
            { id: 'iete', label: 'IETE Facts', color: 'sky', icon: '🏛️' },
            { id: 'search', label: 'Find Diagrams', color: 'emerald', icon: '🖼️' },
          ].map(btn => (
            <button 
              key={btn.id}
              onClick={() => handleAction(btn.id as ToolkitAction)}
              disabled={isLoading}
              className={`flex items-center gap-2.5 whitespace-nowrap px-4 py-3 bg-${btn.color}-600/10 border border-${btn.color}-500/20 rounded-xl text-${btn.color}-400 text-[10px] font-black uppercase tracking-[0.1em] hover:bg-${btn.color}-600/20 active:scale-95 transition-all disabled:opacity-30 disabled:cursor-not-allowed`}
            >
              <span className="text-base">{btn.icon}</span>
              {btn.label}
            </button>
          ))}
        </div>

        {/* Message Input Terminal */}
        <form onSubmit={handleSend} className="flex gap-3 max-w-4xl mx-auto items-center">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*,audio/*,video/*" className="hidden" />

          <button 
            type="button" 
            onClick={() => fileInputRef.current?.click()} 
            disabled={isLoading} 
            className="p-4 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400 hover:bg-white/10 hover:border-blue-500/30 transition-all disabled:opacity-30 flex-shrink-0 shadow-lg shadow-black/20"
            title="Upload Technical File"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
            </svg>
