import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps {
  user: UserProfile;
}

type ToolkitAction = 'extract' | 'solve' | 'search' | 'debug' | 'code' | 'component' | 'pinout' | 'iete' | 'soundtrack';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const hours = new Date().getHours();
    let greeting = 'Hello';
    if (hours < 12) greeting = 'Good morning';
    else if (hours < 17) greeting = 'Good afternoon';
    else greeting = 'Good evening';

    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `${greeting}, ${user.name}! I'm IETE Bot. I'm ready to assist with technical analysis, text extraction from images, or engineering queries. Use the toolkit below for specialized modes.`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setSelectedMedia({ data: base64String, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStop = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    setIsLoading(false);
    setActiveTool(null);
  };

  const handleAction = async (type: ToolkitAction) => {
    if (isLoading) return;

    // Explicit requirement checks
    const mediaRequired = ['extract', 'debug', 'component', 'soundtrack'].includes(type);
    if (mediaRequired && !selectedMedia) {
      alert(`The ${type.toUpperCase()} tool requires an uploaded file.`);
      return;
    }

    setActiveTool(type);

    let prompt = "";
    const lastUserMsg = [...messages].reverse().find(m => m.role === 'user')?.content || "";

    switch(type) {
      case 'extract': prompt = "TASK: EXTRACT TEXT (OCR). Please identify and transcribe ALL text visible in this image. Format it precisely."; break;
      case 'solve': prompt = "TASK: PROBLEM SOLVER. Provide a rigorous, step-by-step engineering solution for the problem shown or described."; break;
      case 'search': prompt = "TASK: VISUAL SEARCH. Find professional datasheets, schematics, or diagrams related to: " + (lastUserMsg || "latest electronics"); break;
      case 'debug': prompt = "TASK: CIRCUIT DEBUG. Analyze this PCB/Schematic for potential errors, shorts, or design flaws."; break;
      case 'code': prompt = "TASK: LOGIC ANALYSIS. Analyze and explain the logic of this code or technical flow clearly."; break;
      case 'component': prompt = "TASK: IDENTIFY COMPONENT. Tell me the name, specs, and typical use cases for this electronic part."; break;
      case 'pinout': prompt = "TASK: PINOUT GUIDE. Provide the pinout and connection map for the component mentioned or shown."; break;
      case 'iete': prompt = "TASK: IETE KNOWLEDGE. Provide facts about IETE history, student chapters, or membership benefits."; break;
      case 'soundtrack': prompt = "TASK: SOUND ID. Identify the audio signature or soundtrack in this file."; break;
    }

    const mediaToProcess = selectedMedia;
    setSelectedMedia(null);

    try {
      await processMessage(prompt, mediaToProcess || undefined);
    } finally {
      // Always reset active tool to prevent "stuck" UI
      setActiveTool(null);
    }
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading) return;

    setIsLoading(true);
    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media?.mimeType.startsWith('image/') ? media : undefined
    };

    setMessages(prev => [...prev, userMessage]);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMessage]);

    try {
      let fullContent = '';
      let sources: { title: string; uri: string }[] = [];
      const streamResponse = await geminiService.sendMessageStream(text, media);

      for await (const chunk of streamResponse) {
        if (!isLoading) break; // Handle manual stop

        fullContent += chunk.text || "";
        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
          groundingChunks.forEach((c: any) => {
            if (c.web && !sources.find(s => s.uri === c.web.uri)) {
              sources.push({ title: c.web.title, uri: c.web.uri });
            }
          });
        }

        setMessages(prev => prev.map(msg => 
          msg.id === assistantMessageId ? { ...msg, content: fullContent, sources: sources.length > 0 ? sources : undefined } : msg
        ));
      }

      geminiService.updateHistory('user', [{ text: text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);

    } catch (error: any) {
      console.error("[IETE Bot] Process Error:", error);
      setMessages(prev => prev.map(msg => 
        msg.id === assistantMessageId ? { ...msg, content: `System Note: ${error.message || "Operation interrupted. Please try again."}` } : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading) return;
    const txt = input;
    const med = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    processMessage(txt || (med ? "Analyze this file upload." : ""), med || undefined);
  };

  return (
    <div className="flex-1 flex flex-col dark-glass-card rounded-[2rem] shadow-2xl overflow-hidden animate-in fade-in slide-in-from-bottom-8 duration-700 h-[calc(100vh-220px)] relative border border-white/5">
      <div className="scan-line"></div>

      {/* Scrollable Chat Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar chat-blueprint relative">
        <div className="watermark-overlay" style={{ backgroundImage: `url(${BOT_LOGO})`, opacity: 0.03 }}></div>
        {messages.map((msg, idx) => {
          const isLatest = idx === messages.length - 1;
          return (
            <div key={msg.id} className={`flex relative z-10 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] md:max-w-[80%] flex gap-3.5 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-10 h-10 rounded-xl flex-shrink-0 flex items-center justify-center shadow-lg border ${msg.role === 'user' ? 'bg-blue-600 border-blue-500' : 'bg-white border-white/20'}`}>
                  {msg.role === 'user' ? (
                    <span className="text-white font-black text-sm">{user.name[0]}</span>
                  ) : <img src={BOT_LOGO} className="w-full h-full object-contain p-1.5" alt="Bot" />}
                </div>
                <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  {msg.image && (
                    <div className="rounded-2xl overflow-hidden border border-white/20 shadow-2xl max-w-sm">
                      <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-64 object-cover" alt="Data" />
                    </div>
                  )}
                  <div className={`rounded-2xl px-6 py-4 shadow-xl relative transition-all duration-300 ${
                    msg.role === 'user' ? 'bg-blue-700 text-white rounded-tr-none user-bubble-glow' : 'bg-white text-slate-900 rounded-tl-none border border-slate-200'
                  }`}>
                    <div className="whitespace-pre-wrap text-[14px] leading-relaxed font-medium">
                      {msg.content || (isLoading && isLatest && msg.role === 'assistant' ? (
                        <div className="flex flex-col gap-2 py-1">
                          <div className="flex items-center gap-2">
                            <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce"></div>
                            <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                            <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                          </div>
                          <span className="text-[9px] uppercase font-black text-blue-500 tracking-widest opacity-80">
                            {activeTool ? `${activeTool.replace('_',' ')} MODE ACTIVE` : "Processing Query..."}
                          </span>
                        </div>
                      ) : null)}
                    </div>
                    {msg.sources && (
                      <div className="mt-4 pt-3 border-t border-slate-100 flex flex-wrap gap-2">
                        {msg.sources.map((s, i) => (
                          <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[10px] bg-blue-50 text-blue-700 px-3 py-1.5 rounded-full border border-blue-100 hover:bg-blue-100 transition-colors font-bold uppercase tracking-wider">
                            {s.title || "Reference"}
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Control Station */}
      <div className="p-4 md:p-6 bg-slate-950/95 backdrop-blur-3xl border-t border-white/10 z-20">

        {/* Upload Status */}
        {selectedMedia && (
          <div className="flex items-center gap-3 mb-4 animate-in slide-in-from-bottom-2 bg-blue-500/10 p-3 rounded-2xl border border-blue-500/20">
            <div className="relative group">
              {selectedMedia.mimeType.startsWith('image/') ? (
                <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-14 w-14 object-cover rounded-xl border-2 border-blue-500" alt="Preview" />
              ) : (
                <div className="h-14 w-14 bg-blue-900/40 border-2 border-blue-500 rounded-xl flex items-center justify-center">
                  <svg className="w-7 h-7 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" strokeWidth={2} /></svg>
                </div>
              )}
              <button onClick={() => setSelectedMedia(null)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center text-[10px] shadow-lg hover:bg-red-600 transition-colors">✕</button>
            </div>
            <div className="flex flex-col">
              <p className="text-[10px] text-blue-400 font-black uppercase tracking-widest">Media Cached</p>
              <p className="text-[9px] text-slate-500 font-bold">Select a Tool or click Send</p>
            </div>
          </div>
        )}

        {/* Toolkit Matrix */}
        <div className="flex gap-2 mb-5 overflow-x-auto pb-2 no-scrollbar">
          {[
            { id: 'extract', label: 'Extract Text', color: 'blue', icon: '📄' },
            { id: 'solve', label: 'Solve Problem', color: 'indigo', icon: '🧠' },
            { id: 'soundtrack', label: 'Soundtrack ID', color: 'purple', icon: '🎵' },
            { id: 'debug', label: 'Circuit Debug', color: 'red', icon: '⚡' },
            { id: 'component', label: 'Identify Part', color: 'amber', icon: '🔍' },
            { id: 'pinout', label: 'Pinout Guide', color: 'pink', icon: '🔌' },
            { id: 'code', label: 'Logic Check', color: 'orange', icon: '💻' },
            { id: 'iete', label: 'IETE Facts', color: 'sky', icon: '🏛️' },
            { id: 'search', label: 'Get Diagrams', color: 'emerald', icon: '🖼️' },
          ].map(btn => (
            <button 
              key={btn.id}
              onClick={() => handleAction(btn.id as ToolkitAction)}
              disabled={isLoading}
              className={`flex items-center gap-2.5 whitespace-nowrap px-4 py-2.5 bg-${btn.color}-600/10 border border-${btn.color}-500/20 rounded-xl text-${btn.color}-400 text-[10px] font-black uppercase tracking-[0.1em] hover:bg-${btn.color}-600/20 active:scale-95 transition-all disabled:opacity-30`}
            >
              <span className="text-sm">{btn.icon}</span>
              {btn.label}
            </button>
          ))}
        </div>

        {/* Input Bar */}
        <form onSubmit={handleSend} className="flex gap-3 max-w-4xl mx-auto items-center">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*,audio/*,video/*" className="hidden" />

          <button 
            type="button" 
            onClick={() => fileInputRef.current?.click()} 
            disabled={isLoading} 
            className="p-4 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400 hover:border-blue-500/30 transition-all flex-shrink-0 shadow-lg"
            title="Upload Media"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
            </svg>
          </button>

          <div className="flex-1 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={isLoading ? "IETE Bot is thinking..." : "Ask me anything..."}
              disabled={isLoading}
              className="w-full px-6 py-4 rounded-2xl bg-white/5 border border-white/10 text-white focus:ring-2 focus:ring-blue-500/50 focus:bg-white/10 outline-none disabled:opacity-50 text-sm font-semibold transition-all"
            />
          </div>

          <button
            type={isLoading ? "button" : "submit"}
            onClick={isLoading ? handleStop : undefined}
            disabled={!isLoading && !input.trim() && !selectedMedia}
            className={`px-8 py-4 ${isLoading ? 'bg-red-600 shadow-red-900/40' : 'bg-gradient-to-br from-blue-600 to-blue-800 shadow-blue-900/40'} text-white font-black rounded-2xl uppercase tracking-[0.2em] text-[10px] shadow-xl transition-all hover:scale-[1.02] active:scale-95 flex-shrink-0 flex items-center gap-2`}
          >
            {isLoading ? (
              <>
                <div className="w-4 h-4 border-2 border-t-transparent border-white rounded-full animate-spin" />
                Stop
              </>
            ) : (
              <>
                Send
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                  <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
                </svg>
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatInterface;

