  return (
    <div className="flex-1 flex flex-col items-center justify-center min-h-[60vh] py-6 animate-in fade-in zoom-in duration-300">
      <div className="w-full max-w-lg p-8 md:p-10 dark-glass-card rounded-[2.5rem] border border-white/10 shadow-2xl relative overflow-hidden text-center">

        <div className="absolute -top-24 -left-24 w-64 h-64 bg-blue-600/10 blur-[100px] pointer-events-none rounded-full"></div>
        <div className="absolute -bottom-24 -right-24 w-64 h-64 bg-indigo-600/10 blur-[100px] pointer-events-none rounded-full"></div>

        <div className="mb-8 flex flex-col items-center relative z-10">
          <div className="w-20 h-20 bg-white rounded-2xl flex items-center justify-center shadow-2xl p-2 border border-white/20 mb-4 transform hover:scale-105 transition-transform">
             <img 
              src="https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4" 
              alt="IETE" 
              className="w-full h-full object-contain"
            />
          </div>
          <h2 className="text-3xl font-black text-white tracking-tighter uppercase mb-1">IETE Bot</h2>
          <p className="text-blue-400 font-bold text-[9px] uppercase tracking-[0.4em]">v3.3 Engineering Core</p>
        </div>

        <p className="text-slate-400 text-sm mb-10 leading-relaxed font-medium">
          Identify yourself to access the professional engineering terminal.
        </p>

        <form onSubmit={handleSubmit} className="w-full space-y-5 relative z-10">
          <div className="text-left">
            <input
              type="text"
              id="name"
              autoFocus
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Enter your name..."
              className="w-full px-6 py-4 rounded-2xl bg-white/5 border border-white/10 text-white text-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder:text-slate-700 font-semibold"
              required
              autoComplete="off"
