import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps {
  user: UserProfile;
}

type ToolkitAction = 'extract' | 'solve' | 'search' | 'debug' | 'code' | 'component' | 'pinout' | 'iete' | 'soundtrack';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const hours = new Date().getHours();
    const greeting = hours < 12 ? 'Good morning' : hours < 17 ? 'Good afternoon' : 'Good evening';

    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `${greeting}, ${user.name}. I am IETE Bot. Upload an image of a problem, schematic, or text, and use the toolkit below for processing.`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setSelectedMedia({ data: base64String, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const resetState = () => {
    setIsLoading(false);
    setActiveTool(null);
  };

  const handleAction = async (type: ToolkitAction) => {
    if (isLoading) return;

    // Safety check for media
    const mediaRequired = ['extract', 'debug', 'component', 'soundtrack'].includes(type);
    if (mediaRequired && !selectedMedia) {
      alert(`Media upload required for ${type.toUpperCase()}`);
      return;
    }

    setActiveTool(type);

    let prompt = "";
    switch(type) {
      case 'extract': prompt = "CORE TOOL: HIGH-PRECISION OCR. I need you to extract every single word from this image. Do not summarize. Just provide the raw text found."; break;
      case 'solve': prompt = "CORE TOOL: PROBLEM SOLVER. Provide a step-by-step solution for the technical problem shown here."; break;
      case 'search': prompt = "CORE TOOL: VISUAL SEARCH. Research related technical documents for the visible topic."; break;
      case 'debug': prompt = "CORE TOOL: CIRCUIT ANALYZER. Check this circuit diagram for design errors or missing links."; break;
      case 'code': prompt = "CORE TOOL: LOGIC ANALYZER. Explain the logic of this code or technical flow."; break;
      case 'component': prompt = "CORE TOOL: PART ID. Identify this electronic component and give its key specs."; break;
      case 'pinout': prompt = "CORE TOOL: PINOUT. Show me the pinout for this specific part."; break;
      case 'iete': prompt = "CORE TOOL: IETE INFO. Tell me about IETE memberships and centers."; break;
      case 'soundtrack': prompt = "CORE TOOL: AUDIO ID. Identify the sound signature in this file."; break;
    }

    const currentMedia = selectedMedia;
    setSelectedMedia(null);

    try {
      await processMessage(prompt, currentMedia || undefined);
    } finally {
      resetState();
    }
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading) return;

    setIsLoading(true);
    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media?.mimeType.startsWith('image/') ? media : undefined
    };

    setMessages(prev => [...prev, userMessage]);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMessage]);

    try {
      let fullContent = '';
      let sources: { title: string; uri: string }[] = [];
      const streamResponse = await geminiService.sendMessageStream(text, media);

      for await (const chunk of streamResponse) {
        fullContent += chunk.text || "";
        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
          groundingChunks.forEach((c: any) => {
            if (c.web && !sources.find(s => s.uri === c.web.uri)) {
              sources.push({ title: c.web.title, uri: c.web.uri });
            }
          });
        }

        setMessages(prev => prev.map(msg => 
          msg.id === assistantMessageId ? { ...msg, content: fullContent, sources: sources.length > 0 ? sources : undefined } : msg
        ));
      }

      geminiService.updateHistory('user', [{ text: text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);

    } catch (error: any) {
      setMessages(prev => prev.map(msg => 
        msg.id === assistantMessageId ? { ...msg, content: `Error: ${error.message || "Request timed out."}` } : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading) return;
    const txt = input;
    const med = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    processMessage(txt || "Analyze this content.", med || undefined);
  };

  return (
    <div className="flex-1 flex flex-col dark-glass-card rounded-[2rem] shadow-2xl overflow-hidden h-[calc(100vh-200px)] relative border border-white/10">
      <div className="scan-line"></div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar chat-blueprint relative z-10">
        <div className="watermark-overlay" style={{ backgroundImage: `url(${BOT_LOGO})`, opacity: 0.03 }}></div>
        {messages.map((msg, idx) => {
          const isLatest = idx === messages.length - 1;
          return (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] md:max-w-[85%] flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-9 h-9 rounded-xl flex-shrink-0 flex items-center justify-center shadow-lg border ${msg.role === 'user' ? 'bg-blue-600 border-blue-500' : 'bg-white border-white/20'}`}>
                  {msg.role === 'user' ? (
                    <span className="text-white font-black text-xs">{user.name[0]}</span>
                  ) : <img src={BOT_LOGO} className="w-full h-full object-contain p-1.5" alt="IETE" />}
                </div>
                <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  {msg.image && (
                    <div className="rounded-2xl overflow-hidden border border-white/20 shadow-2xl max-w-sm">
                      <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-60 object-cover" alt="User Data" />
                    </div>
                  )}
                  <div className={`rounded-2xl px-5 py-3.5 shadow-xl relative transition-all duration-300 ${
                    msg.role === 'user' ? 'bg-blue-700 text-white rounded-tr-none' : 'bg-white text-slate-900 rounded-tl-none border border-slate-200'
                  }`}>
                    <div className="whitespace-pre-wrap text-[14px] leading-relaxed font-medium">
                      {msg.content || (isLoading && isLatest && msg.role === 'assistant' ? (
                        <div className="flex flex-col gap-2 py-1">
                          <div className="flex items-center gap-2">
                            <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse"></div>
                            <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse [animation-delay:-0.1s]"></div>
                            <div className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse [animation-delay:-0.2s]"></div>
                          </div>
                          <span className="text-[8px] uppercase font-black text-blue-500 tracking-widest">{activeTool ? `${activeTool.toUpperCase()} MODE` : "Analyzing..."}</span>
                        </div>
                      ) : null)}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Controller Block */}
      <div className="p-4 md:p-6 bg-slate-950/98 backdrop-blur-3xl border-t border-white/10 z-20">

        {selectedMedia && (
          <div className="flex items-center gap-3 mb-4 animate-in slide-in-from-bottom-1 bg-blue-600/10 p-2.5 rounded-2xl border border-blue-500/30">
            <div className="relative group">
              <div className="h-12 w-12 bg-blue-900/40 border border-blue-500 rounded-lg flex items-center justify-center overflow-hidden">
                {selectedMedia.mimeType.startsWith('image/') ? <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="w-full h-full object-cover" /> : "📄"}
              </div>
              <button onClick={() => setSelectedMedia(null)} className="absolute -top-2 -right-2 bg-red-600 text-white rounded-full w-5 h-5 flex items-center justify-center text-[10px] shadow-lg">✕</button>
            </div>
            <p className="text-[10px] text-blue-400 font-black uppercase tracking-widest">Media Uplink Ready</p>
          </div>
        )}

        {/* Rapid Toolkit Matrix */}
        <div className="flex gap-2 mb-4 overflow-x-auto pb-2 no-scrollbar">
          {[
            { id: 'extract', label: 'Extract Text', color: 'blue', icon: '📄' },
            { id: 'solve', label: 'Problem Solver', color: 'indigo', icon: '🧠' },
            { id: 'soundtrack', label: 'Soundtrack ID', color: 'purple', icon: '🎵' },
            { id: 'debug', label: 'Circuit Debug', color: 'red', icon: '⚡' },
            { id: 'component', label: 'Identify Part', color: 'amber', icon: '🔍' },
          ].map(btn => (
            <button 
              key={btn.id}
              onClick={() => handleAction(btn.id as ToolkitAction)}
              disabled={isLoading}
              className={`flex items-center gap-2 whitespace-nowrap px-4 py-2.5 bg-${btn.color}-600/10 border border-${btn.color}-500/20 rounded-xl text-${btn.color}-400 text-[10px] font-black uppercase tracking-[0.1em] hover:bg-${btn.color}-600/20 active:scale-95 disabled:opacity-30`}
            >
              <span>{btn.icon}</span> {btn.label}
            </button>
          ))}
        </div>

        {/* Input Dock */}
        <form onSubmit={handleSend} className="flex gap-3 max-w-4xl mx-auto items-center">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*,audio/*" className="hidden" />

          <button type="button" onClick={() => fileInputRef.current?.click()} disabled={isLoading} className="p-4 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400 transition-all flex-shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" strokeWidth={2} /></svg>
          </button>

          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type your query here..."
            disabled={isLoading}
            className="flex-1 px-5 py-4 rounded-2xl bg-white/5 border border-white/10 text-white focus:ring-1 focus:ring-blue-500 outline-none disabled:opacity-50 text-sm font-semibold transition-all"
          />

          <button
            type="submit"
            disabled={isLoading || (!input.trim() && !selectedMedia)}
            className="px-8 py-4 bg-gradient-to-br from-blue-600 to-blue-800 text-white font-black rounded-2xl uppercase tracking-[0.1em] text-[10px] shadow-lg disabled:opacity-30 transition-all hover:brightness-110 active:scale-95 flex-shrink-0"
          >
            {isLoading ? <div className="w-4 h-4 border-2 border-t-transparent border-white rounded-full animate-spin" /> : "Run Output"}
          </button>
        </form>
      </div>
    </div>
  );
};

