      // Otherwise, "Arm" the tool and wait for upload
      setActiveTool(type);
    }
  };

  const executeTool = async (type: ToolkitAction, media: { data: string; mimeType: string }) => {
    if (isLoading) return;

    setIsLoading(true);
    let prompt = "";
    switch(type) {
      case 'extract': prompt = "CORE TOOL: HIGH-PRECISION OCR. Transcribe all text from this image exactly as it appears. Focus on engineering symbols and handwritten notes."; break;
