    // Clear states before processing
    setSelectedMedia(null);
    setActiveTool(null);

    await processMessage(prompt, media);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading && !media) return; // Allow internal calls to set isLoading themselves

    setIsLoading(true);
    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media?.mimeType.startsWith('image/') ? media : undefined
