import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps {
  user: UserProfile;
}

type ToolkitAction = 'extract' | 'solve' | 'search' | 'debug' | 'code' | 'component' | 'pinout' | 'iete' | 'soundtrack';

// Internal component for the typing effect
const TypewriterText: React.FC<{ text: string; isStreaming: boolean }> = ({ text, isStreaming }) => {
  const [displayedText, setDisplayedText] = useState('');
  const [currentIndex, setCurrentIndex] = useState(0);
  const typingSpeed = 15; // ms per character

  useEffect(() => {
    if (text.length > currentIndex) {
      const timeout = setTimeout(() => {
        // If the gap is large (e.g. fast stream), take more characters to catch up
        const charsToTake = text.length - currentIndex > 20 ? 5 : 1;
        setDisplayedText(text.substring(0, currentIndex + charsToTake));
        setCurrentIndex(currentIndex + charsToTake);
      }, typingSpeed);
      return () => clearTimeout(timeout);
    }
  }, [text, currentIndex]);

  return (
    <div className="whitespace-pre-wrap text-[14px] leading-relaxed font-medium">
      {displayedText}
      {(isStreaming || displayedText.length < text.length) && (
        <span className="inline-block w-2 h-4 ml-1 bg-blue-500 animate-pulse align-middle">_</span>
      )}
    </div>
  );
};

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const hours = new Date().getHours();
    const greeting = hours < 12 ? 'Good morning' : hours < 17 ? 'Good afternoon' : 'Good evening';

    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `${greeting}, ${user.name}. I am IETE Bot. You can select a tool first then upload your file, or upload first then select a tool. I'm ready to process your data.`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        const media = { data: base64String, mimeType: file.type };
        setSelectedMedia(media);

        if (activeTool) {
          executeTool(activeTool, media);
        }
      };
      reader.readAsDataURL(file);
    }
    e.target.value = '';
  };

  const handleActionClick = (type: ToolkitAction) => {
    if (isLoading) return;
    if (selectedMedia) {
      executeTool(type, selectedMedia);
    } else {
      setActiveTool(type);
    }
  };

  const executeTool = async (type: ToolkitAction, media: { data: string; mimeType: string }) => {
    if (isLoading) return;

    setIsLoading(true);
    let prompt = "";
    switch(type) {
      case 'extract': prompt = "CORE TOOL: HIGH-PRECISION OCR. Transcribe all text from this image exactly as it appears. Focus on engineering symbols and handwritten notes."; break;
      case 'solve': prompt = "CORE TOOL: PROBLEM SOLVER. Solve the engineering problem visible in this image step-by-step."; break;
      case 'debug': prompt = "CORE TOOL: CIRCUIT ANALYZER. Analyze this schematic/PCB for design errors or faulty paths."; break;
      case 'code': prompt = "CORE TOOL: LOGIC ANALYZER. Explain the logic of the code or system flow shown."; break;
      case 'component': prompt = "CORE TOOL: PART ID. Identify this electronic component and its specifications."; break;
      case 'pinout': prompt = "CORE TOOL: PINOUT. Provide the pinout connections for the visible component."; break;
      case 'iete': prompt = "CORE TOOL: IETE INFO. Provide technical or institutional details related to this query."; break;
      case 'soundtrack': prompt = "CORE TOOL: AUDIO ID. Identify the audio signature or track in this file."; break;
    }

    setSelectedMedia(null);
    setActiveTool(null);
    await processMessage(prompt, media);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading && !media) return;

    setIsLoading(true);
    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media?.mimeType.startsWith('image/') ? media : undefined
    };

    setMessages(prev => [...prev, userMessage]);

    const assistantMessageId = (Date.now() + 1).toString();
    const assistantMessage: Message = {
      id: assistantMessageId,
      role: 'assistant',
      content: '',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, assistantMessage]);

    try {
      let fullContent = '';
      const streamResponse = await geminiService.sendMessageStream(text, media);

      for await (const chunk of streamResponse) {
        fullContent += chunk.text || "";
        setMessages(prev => prev.map(msg => 
          msg.id === assistantMessageId ? { ...msg, content: fullContent } : msg
        ));
      }

      geminiService.updateHistory('user', [{ text: text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);

    } catch (error: any) {
      setMessages(prev => prev.map(msg => 
        msg.id === assistantMessageId ? { ...msg, content: `Neural Error: ${error.message || "Connection interrupted."}` } : msg
      ));
    } finally {
      setIsLoading(false);
      setActiveTool(null);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading) return;
    const txt = input;
    const med = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    setActiveTool(null);
    processMessage(txt || "Analyzing uploaded content...", med || undefined);
  };

  return (
    <div className="flex-1 flex flex-col dark-glass-card rounded-[2rem] shadow-2xl overflow-hidden h-[calc(100vh-180px)] relative border border-white/10">
      <div className="scan-line"></div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar chat-blueprint relative z-10">
        <div className="watermark-overlay" style={{ backgroundImage: `url(${BOT_LOGO})`, opacity: 0.02 }}></div>
        {messages.map((msg, idx) => {
          const isLatest = idx === messages.length - 1;
          return (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] md:max-w-[85%] flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-9 h-9 rounded-xl flex-shrink-0 flex items-center justify-center shadow-lg border ${msg.role === 'user' ? 'bg-blue-600 border-blue-500' : 'bg-white border-white/20'}`}>
                  {msg.role === 'user' ? (
                    <span className="text-white font-black text-xs">{user.name[0]}</span>
                  ) : <img src={BOT_LOGO} className="w-full h-full object-contain p-1.5" alt="Bot" />}
                </div>
                <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  {msg.image && (
                    <div className="rounded-2xl overflow-hidden border border-white/20 shadow-2xl max-w-sm">
                      <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-60 object-cover" alt="Uplink" />
                    </div>
                  )}
                  <div className={`rounded-2xl px-5 py-3.5 shadow-xl relative transition-all duration-300 ${
                    msg.role === 'user' ? 'bg-blue-700 text-white rounded-tr-none' : 'bg-white text-slate-900 rounded-tl-none border border-slate-200'
                  }`}>
                    {msg.role === 'assistant' ? (
                      <TypewriterText text={msg.content} isStreaming={isLoading && isLatest} />
                    ) : (
                      <div className="whitespace-pre-wrap text-[14px] leading-relaxed font-medium">{msg.content}</div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="p-4 md:p-6 bg-slate-950/98 backdrop-blur-3xl border-t border-white/10 z-20">

        {(selectedMedia || activeTool) && (
          <div className="flex items-center justify-between mb-4 animate-in slide-in-from-bottom-2">
            <div className="flex items-center gap-3 bg-blue-600/10 p-2.5 rounded-2xl border border-blue-500/30 w-full">
              <div className="h-10 w-10 bg-blue-900/40 border border-blue-500 rounded-lg flex items-center justify-center overflow-hidden flex-shrink-0">
                {selectedMedia ? (
                   selectedMedia.mimeType.startsWith('image/') ? <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="w-full h-full object-cover" /> : "📄"
                ) : <div className="animate-pulse text-blue-400">⏳</div>}
              </div>
              <div className="flex flex-col flex-1">
                <p className="text-[10px] text-blue-400 font-black uppercase tracking-widest">
                  {activeTool ? `Arming Mode: ${activeTool.toUpperCase()}` : 'Buffer Loaded'}
                </p>
                <p className="text-[9px] text-slate-400 font-bold">
                  {activeTool && !selectedMedia ? "Awaiting uplink to fire command..." : "System ready."}
                </p>
              </div>
              <button onClick={() => { setSelectedMedia(null); setActiveTool(null); }} className="p-2 text-slate-400 hover:text-red-500 transition-colors">✕</button>
            </div>
          </div>
        )}

        <div className="flex gap-2 mb-4 overflow-x-auto pb-2 no-scrollbar">
          {[
            { id: 'extract', label: 'Extract Text', color: 'blue', icon: '📄' },
            { id: 'solve', label: 'Problem Solver', color: 'indigo', icon: '🧠' },
            { id: 'debug', label: 'Circuit Debug', color: 'red', icon: '⚡' },
            { id: 'component', label: 'Identify Part', color: 'amber', icon: '🔍' },
            { id: 'pinout', label: 'Pinout', color: 'pink', icon: '🔌' },
            { id: 'code', label: 'Logic Check', color: 'orange', icon: '💻' },
          ].map(btn => (
            <button 
              key={btn.id}
              onClick={() => handleActionClick(btn.id as ToolkitAction)}
              disabled={isLoading}
              className={`flex items-center gap-2 whitespace-nowrap px-4 py-3 border rounded-xl text-[10px] font-black uppercase tracking-[0.1em] transition-all active:scale-95 disabled:opacity-30 ${
                activeTool === btn.id 
                  ? `bg-${btn.color}-600/40 border-${btn.color}-400 text-white shadow-lg shadow-${btn.color}-900/20` 
                  : `bg-${btn.color}-600/10 border-${btn.color}-500/20 text-${btn.color}-400 hover:bg-${btn.color}-600/20`
              }`}
            >
              <span>{btn.icon}</span> {btn.label}
            </button>
          ))}
        </div>

        <form onSubmit={handleSend} className="flex gap-3 max-w-4xl mx-auto items-center">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*,audio/*" className="hidden" />

          <button type="button" onClick={() => fileInputRef.current?.click()} disabled={isLoading} className="p-4 bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:text-blue-400 hover:border-blue-500/40 transition-all flex-shrink-0 shadow-xl">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" strokeWidth={2} /></svg>
          </button>

          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={activeTool ? `Armed: ${activeTool.toUpperCase()}. Type context...` : "Type engineering query..."}
            disabled={isLoading}
            className="flex-1 px-5 py-4 rounded-2xl bg-white/5 border border-white/10 text-white focus:ring-1 focus:ring-blue-500/50 outline-none disabled:opacity-50 text-sm font-semibold transition-all placeholder:text-slate-600"
          />

          <button
            type="submit"
            disabled={isLoading || (!input.trim() && !selectedMedia)}
            className="px-8 py-4 bg-gradient-to-br from-blue-600 to-blue-800 text-white font-black rounded-2xl uppercase tracking-[0.1em] text-[10px] shadow-lg shadow-blue-900/30 transition-all hover:brightness-110 active:scale-95 flex-shrink-0"
          >
            {isLoading ? <div className="w-4 h-4 border-2 border-t-transparent border-white rounded-full animate-spin" /> : "Run Output"}
          </button>
        </form>
      </div>
    </div>
  );
};

