import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps {
  user: UserProfile;
}

type ToolkitAction = 'extract' | 'solve' | 'search' | 'debug' | 'code' | 'component' | 'pinout' | 'iete' | 'soundtrack';

const TypewriterText: React.FC<{ text: string; isStreaming: boolean }> = ({ text, isStreaming }) => {
  const [displayedText, setDisplayedText] = useState('');
  const [currentIndex, setCurrentIndex] = useState(0);
  const typingSpeed = 15;

  useEffect(() => {
    if (text.length > currentIndex) {
      const timeout = setTimeout(() => {
        const charsToTake = text.length - currentIndex > 20 ? 5 : 1;
        setDisplayedText(text.substring(0, currentIndex + charsToTake));
        setCurrentIndex(currentIndex + charsToTake);
      }, typingSpeed);
      return () => clearTimeout(timeout);
    }
  }, [text, currentIndex]);

  return (
    <div className="whitespace-pre-wrap text-[14px] leading-relaxed font-medium">
      {displayedText}
      {(isStreaming || displayedText.length < text.length) && (
        <span className="inline-block w-2 h-4 ml-1 bg-[var(--accent-color)] animate-pulse align-middle">_</span>
      )}
    </div>
  );
};

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const hours = new Date().getHours();
    const greeting = hours < 12 ? 'Good morning' : hours < 17 ? 'Good afternoon' : 'Good evening';

    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `${greeting}, ${user.name}. I am IETE Bot. How can I assist you with electronics or telecommunication today?`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isLoading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        const media = { data: base64String, mimeType: file.type };
        setSelectedMedia(media);
        if (activeTool) executeTool(activeTool, media);
      };
      reader.readAsDataURL(file);
    }
    e.target.value = '';
  };

  const handleActionClick = (type: ToolkitAction) => {
    if (isLoading) return;
    if (selectedMedia) executeTool(type, selectedMedia);
    else setActiveTool(type);
  };

  const executeTool = async (type: ToolkitAction, media: { data: string; mimeType: string }) => {
    if (isLoading) return;
    setIsLoading(true);
    let prompt = "";
    switch(type) {
      case 'extract': prompt = "CORE TOOL: OCR. Extract all text from this image precisely."; break;
      case 'solve': prompt = "CORE TOOL: PROBLEM SOLVER. Provide a technical solution for this image content."; break;
      case 'debug': prompt = "CORE TOOL: CIRCUIT DEBUG. Analyze this schematic for errors."; break;
      case 'component': prompt = "CORE TOOL: PART ID. Identify this part and its specifications."; break;
      case 'pinout': prompt = "CORE TOOL: PINOUT. Show pin connections for this component."; break;
      default: prompt = "Process this media content.";
    }
    setSelectedMedia(null);
    setActiveTool(null);
    await processMessage(prompt, media);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading && !media) return;
    setIsLoading(true);
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media?.mimeType.startsWith('image/') ? media : undefined
    };
    setMessages(prev => [...prev, userMessage]);
    const assistantMessageId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantMessageId, role: 'assistant', content: '', timestamp: new Date() }]);

    try {
      let fullContent = '';
      const streamResponse = await geminiService.sendMessageStream(text, media);
      for await (const chunk of streamResponse) {
        fullContent += chunk.text || "";
        setMessages(prev => prev.map(msg => msg.id === assistantMessageId ? { ...msg, content: fullContent } : msg));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map(msg => msg.id === assistantMessageId ? { ...msg, content: `Error: ${error.message}` } : msg));
    } finally {
      setIsLoading(false);
      setActiveTool(null);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading) return;
    const txt = input;
    const med = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    setActiveTool(null);
    processMessage(txt || "Analyzing data...", med || undefined);
  };

  return (
    <div className="flex-1 flex flex-col theme-glass-card rounded-[2rem] overflow-hidden h-[calc(100vh-180px)] relative transition-all duration-300">
      <div className="scan-line"></div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar chat-blueprint relative z-10">
        <div className="watermark-overlay"></div>
        {messages.map((msg, idx) => {
          const isLatest = idx === messages.length - 1;
          return (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] md:max-w-[85%] flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                <div className={`w-9 h-9 rounded-xl flex-shrink-0 flex items-center justify-center shadow-lg border ${msg.role === 'user' ? 'bg-[var(--accent-color)] border-[var(--accent-color)]' : 'bg-white border-black/10'}`}>
                  {msg.role === 'user' ? <span className="text-white font-black text-xs">{user.name[0]}</span> : <img src={BOT_LOGO} className="w-full h-full object-contain p-1.5" alt="Bot" />}
                </div>
                <div className={`flex flex-col gap-2 ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  {msg.image && (
                    <div className="rounded-2xl overflow-hidden border border-black/10 shadow-lg max-w-sm">
                      <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-60 object-cover" alt="Data" />
                    </div>
                  )}
                  <div className={`rounded-2xl px-5 py-3.5 shadow-md transition-all duration-300 ${
                    msg.role === 'user' ? 'bg-[var(--accent-color)] text-white rounded-tr-none' : 'bg-[var(--header-bg)] text-[var(--text-primary)] rounded-tl-none border border-black/5'
                  }`}>
                    {msg.role === 'assistant' ? (
                      <TypewriterText text={msg.content} isStreaming={isLoading && isLatest} />
                    ) : (
                      <div className="whitespace-pre-wrap text-[14px] leading-relaxed font-medium">{msg.content}</div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="p-4 md:p-6 bg-[var(--header-bg)] border-t border-black/5 z-20">
        <div className="flex gap-2 mb-4 overflow-x-auto pb-2 no-scrollbar">
          {[
            { id: 'extract', label: 'Extract', color: 'blue', icon: '📄' },
            { id: 'solve', label: 'Solve', color: 'indigo', icon: '🧠' },
            { id: 'debug', label: 'Debug', color: 'red', icon: '⚡' },
            { id: 'component', label: 'Part ID', color: 'amber', icon: '🔍' },
          ].map(btn => (
            <button 
              key={btn.id}
              onClick={() => handleActionClick(btn.id as ToolkitAction)}
              disabled={isLoading}
              className={`flex items-center gap-2 px-4 py-2.5 border rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                activeTool === btn.id 
                  ? 'bg-[var(--accent-color)] text-white border-[var(--accent-color)]' 
                  : 'bg-black/5 border-black/5 text-[var(--text-secondary)] hover:bg-black/10'
              }`}
            >
              <span>{btn.icon}</span> {btn.label}
            </button>
          ))}
        </div>

        <form onSubmit={handleSend} className="flex gap-3 max-w-4xl mx-auto items-center">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
          <button type="button" onClick={() => fileInputRef.current?.click()} disabled={isLoading} className="p-4 bg-black/5 rounded-2xl text-[var(--text-secondary)] hover:text-[var(--accent-color)] transition-all flex-shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" strokeWidth={2} /></svg>
          </button>
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Technical query..."
            disabled={isLoading}
            className="flex-1 px-5 py-4 rounded-2xl bg-black/5 text-[var(--text-primary)] outline-none text-sm font-semibold placeholder:opacity-30"
          />
          <button
            type="submit"
            disabled={isLoading || (!input.trim() && !selectedMedia)}
            className="px-8 py-4 bg-[var(--accent-color)] text-white font-black rounded-2xl uppercase tracking-widest text-[10px] shadow-lg transition-all active:scale-95"
          >
            {isLoading ? "..." : "Run"}
          </button>
        </form>
      </div>
    </div>
  );
};

