import { GoogleGenAI } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export interface GroundingSource {
  title: string;
  uri: string;
}

export class GeminiService {
  private ai: GoogleGenAI;
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  initChat(userName: string) {
    this.systemInstruction = `You are IETE Bot, a world-class AI Engineering Mentor for students of The Institution of Electronics and Telecommunication Engineers (IETE). 

    MATHEMATICAL RENDERING RULES:
    - Use LaTeX for ALL mathematical formulas and scientific notation.
    - For inline math, use single dollar signs: $E = mc^2$.
    - For important formulas, derivations, or multi-line equations, use double dollar signs for block display:
      $$
      V = I \times R
      $$
    - Use proper engineering symbols (e.g., \\Omega for Ohms, \\mu F for microfarads, \\pi for pi).
    - Ensure fractions use \\frac{a}{b} and integrals use \\int.

    STUDENT-CENTRIC PROTOCOLS:
    1. EXTRACT TEXT: Flawless OCR for handwritten notes or textbook pages.
    2. PROBLEM SOLVER: Provide step-by-step mathematical derivations with block equations.
    3. VIVA PREP: Generate 5-10 technical interview questions.
    4. DATASHEET: Summarize pinouts and specs for ICs/components.
    5. EXPLAIN CODE: Line-by-line analysis in code blocks.
    6. PROJECT GURU: Suggest innovative IETE-level project ideas.

    TONE & STYLE:
    - Mentor-like and technically rigorous.
    - Address user as ${userName}.
    - Use clear Markdown headings and lists.`;

    this.history = [];
  }

  async sendMessageStream(message: string, mediaData?: { data: string; mimeType: string }) {
    const userParts: any[] = [{ text: message }];

    if (mediaData) {
      userParts.push({
        inlineData: {
          data: mediaData.data,
          mimeType: mediaData.mimeType
        }
      });
    }

    const contents = [
      ...this.history,
      { role: 'user', parts: userParts }
    ];

    try {
      const response = await this.ai.models.generateContentStream({
        model: MODEL_NAME,
        contents,
        config: {
          systemInstruction: this.systemInstruction,
          tools: [{ googleSearch: {} }],
          temperature: 0.4, 
        },
      });
      return response;
    } catch (error: any) {
      if (error.message?.includes('429')) {
        throw new Error("Neural cores throttled (Rate Limit). Please wait 60s.");
      }
      throw new Error(`Technical Fault: ${error.message || "Unknown processing error"}`);
    }
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps { user: UserProfile; }

type ToolkitAction = 
  | 'extract' | 'solve' | 'debug' | 'component' 
  | 'viva' | 'datasheet' | 'code' | 'formula' 
  | 'project' | 'study' | 'pinout';

const TypewriterText: React.FC<{ text: string; isStreaming: boolean; onFinished?: () => void }> = ({ text, isStreaming, onFinished }) => {
  const [displayedText, setDisplayedText] = useState('');
  const [currentIndex, setCurrentIndex] = useState(0);
  const typingSpeed = 10;

  useEffect(() => {
    if (text.length > currentIndex) {
      const timeout = setTimeout(() => {
        // Dynamic speed based on buffer size
        const charsToTake = text.length - currentIndex > 50 ? 20 : (text.length - currentIndex > 20 ? 8 : 2);
        const nextText = text.substring(0, currentIndex + charsToTake);
        setDisplayedText(nextText);
        setCurrentIndex(currentIndex + charsToTake);
      }, typingSpeed);
      return () => clearTimeout(timeout);
    } else if (text.length > 0 && !isStreaming && currentIndex >= text.length) {
      onFinished?.();
    }
  }, [text, currentIndex, isStreaming, onFinished]);

  return (
    <div className="markdown-body">
      <ReactMarkdown 
        remarkPlugins={[remarkMath, remarkGfm]} 
        rehypePlugins={[rehypeKatex]}
      >
        {displayedText}
      </ReactMarkdown>
      {(isStreaming || (text.length > 0 && displayedText.length < text.length)) && (
        <span className="inline-block w-2 h-4 ml-1 bg-[var(--accent-color)] animate-pulse align-middle">_</span>
      )}
    </div>
  );
};

