import { GoogleGenAI } from "@google/genai";

const TEXT_MODEL = 'gemini-3-pro-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export class GeminiService {
  private ai: GoogleGenAI | null = null;
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {
    const apiKey = process.env.API_KEY;
    if (apiKey) {
      this.ai = new GoogleGenAI({ apiKey });
    }
  }

  private getAI() {
    if (!this.ai) {
      if (!process.env.API_KEY) {
        throw new Error("Missing Gemini API Key. Go to Vercel Project Settings > Environment Variables and add API_KEY.");
      }
      this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    }
    return this.ai;
  }

  initChat(userName: string) {
    this.systemInstruction = `You are IETE Bot, a high-level Engineering AI Mentor. 

    CRITICAL INSTRUCTION: RESPONSE LENGTH & DEPTH
    - NEVER provide brief or concise answers. 
    - ALWAYS provide comprehensive, multi-paragraph, and highly detailed explanations.
    - If a user asks a simple question, provide the definition, the underlying physics/logic, the mathematical formula (in LaTeX), and 3 real-world engineering applications.
    - Structure your answers with clear headings, bullet points, and numbered lists.

    MATHEMATICS:
    - Use ONLY LaTeX block formatting for equations:
      $$ [Formula] $$
    - Always define every variable in the formula.

    TONE:
    - Professional, academic, and encouraging. Address the user as ${userName}.`;

    this.history = [];
  }

  async sendMessageStream(message: string, mediaData?: { data: string; mimeType: string }) {
    const ai = this.getAI();
    const userParts: any[] = [{ text: message }];
    if (mediaData) {
      userParts.push({ inlineData: { data: mediaData.data, mimeType: mediaData.mimeType } });
    }

    const contents = [...this.history, { role: 'user', parts: userParts }];

    return await ai.models.generateContentStream({
      model: TEXT_MODEL,
      contents,
      config: {
        systemInstruction: this.systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.7, // Higher temperature for more detailed, creative technical writing
      },
    });
  }

  async generateTechnicalImage(prompt: string) {
    const ai = this.getAI();
    // Enhance the prompt for technical accuracy
    const enhancedPrompt = `A high-quality, professional technical engineering diagram of: ${prompt}. 
    Clean lines, blueprint style, professional labeling, white background, high resolution. 
    Electronics and telecommunication engineering style.`;

    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: { parts: [{ text: enhancedPrompt }] },
      config: {
        imageConfig: { aspectRatio: "16:9" }
      }
    });

    // Extract the image from parts
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return {
          data: part.inlineData.data,
          mimeType: part.inlineData.mimeType
        };
      }
    }
    return null;
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
    // Keep history manageable
    if (this.history.length > 20) this.history.shift();
  }
}

