interface ChatInterfaceProps { user: UserProfile; }

type ToolkitAction = 
  | 'extract' | 'solve' | 'debug' | 'visualize' 
  | 'viva' | 'code' | 'formula' | 'project' | 'pinout';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);
  const [configError, setConfigError] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `Hey, ${user.name}! I am IETE Bot, your advanced Engineering Neural Assistant. I am now equipped with Gemini 3 Pro and 2.5 Image generation capabilities. 

How can I assist you with your electronics, telecommunication, or IT research today? I can solve complex problems, explain theories in depth, or even generate technical diagrams for you.`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);

    if (!process.env.API_KEY) {
      setConfigError("Gemini API Key is missing. Please set 'API_KEY' in Vercel environment variables.");
    }
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading]);

  const handleActionClick = async (type: ToolkitAction) => {
    if (isLoading) return;

    if (type === 'visualize') {
      const topic = prompt("What technical diagram should I generate? (e.g. '5G Network Architecture', 'Bridge Rectifier Circuit')");
      if (topic) {
        await processVisualizer(topic);
      }
      return;
    }

    if (selectedMedia) {
      executeTool(type, selectedMedia);
    } else {
      setActiveTool(type);
    }
  };

  const processVisualizer = async (topic: string) => {
    setIsLoading(true);
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: `Generate a technical diagram for: ${topic}`,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMessage]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: `Generating technical visual for "${topic}"...`, timestamp: new Date() }]);

    try {
      const imageResult = await geminiService.generateTechnicalImage(topic);
      if (imageResult) {
        setMessages(prev => prev.map(msg => 
          msg.id === assistantId 
            ? { ...msg, content: `Here is the technical diagram for **${topic}**.`, image: imageResult } 
            : msg
        ));
      } else {
        throw new Error("Failed to generate image.");
      }
    } catch (e: any) {
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, content: `Error generating visual: ${e.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const executeTool = async (type: ToolkitAction, media: { data: string; mimeType: string }) => {
    setIsLoading(true);
    let toolPrompt = "";
    switch(type) {
      case 'solve': toolPrompt = "Solve this engineering problem in extreme detail with step-by-step LaTeX."; break;
      case 'debug': toolPrompt = "Analyze this circuit or code for errors. Provide a detailed troubleshooting report."; break;
      case 'pinout': toolPrompt = "Identify this IC and provide a comprehensive pinout table and functional description."; break;
      default: toolPrompt = "Analyze this image in depth.";
    }
    setSelectedMedia(null);
    setActiveTool(null);
    await processMessage(toolPrompt, media);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading) return;
    setIsLoading(true);

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media
    };
    setMessages(prev => [...prev, userMessage]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: '', timestamp: new Date() }]);

    try {
      let fullContent = '';
      const stream = await geminiService.sendMessageStream(text, media);

      for await (const chunk of stream) {
        fullContent += chunk.text || "";
        setMessages(prev => prev.map(msg => 
          msg.id === assistantId ? { ...msg, content: fullContent } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, content: `Error: ${error.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;
    const txt = input;
    setInput('');
    processMessage(txt);
  };

  return (
    <div className="flex-1 flex flex-col theme-glass-card rounded-[2rem] overflow-hidden h-[calc(100vh-180px)] relative">
      {configError && <div className="bg-red-600 text-white text-[10px] py-1 text-center font-bold uppercase">{configError}</div>}

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 chat-blueprint">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-4 max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-10 h-10 rounded-xl flex-shrink-0 flex items-center justify-center shadow-md bg-white border border-black/10 overflow-hidden p-1">
                {msg.role === 'user' ? <span className="font-bold text-blue-600">{user.name[0]}</span> : <img src={BOT_LOGO} className="w-full h-full object-contain" />}
              </div>
              <div className="flex flex-col gap-3">
                <div className={`rounded-2xl px-6 py-4 shadow-sm border ${
                  msg.role === 'user' ? 'bg-blue-600 text-white border-blue-500' : 'bg-[var(--card-bg)] text-[var(--text-primary)] border-[var(--border-color)]'
                }`}>
                  <div className="markdown-body prose prose-invert max-w-none">
                    <ReactMarkdown remarkPlugins={[remarkMath, remarkGfm]} rehypePlugins={[rehypeKatex]}>
                      {msg.content}
                    </ReactMarkdown>
                  </div>
                </div>
                {msg.image && (
                  <div className="rounded-2xl overflow-hidden border border-[var(--border-color)] shadow-xl bg-black/20 p-1 group relative">
                    <div className="absolute top-2 left-2 bg-blue-600 text-white text-[8px] px-2 py-0.5 rounded-full font-bold uppercase tracking-widest z-10 opacity-0 group-hover:opacity-100 transition-opacity">AI Generated Illustration</div>
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto rounded-xl max-h-[500px] object-contain bg-white" alt="AI Generated Technical Visual" />
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start animate-pulse">
            <div className="w-10 h-10 rounded-xl bg-blue-600/20 mr-4"></div>
            <div className="h-12 w-48 bg-blue-600/10 rounded-2xl"></div>
          </div>
        )}
      </div>

      <div className="p-4 bg-[var(--header-bg)] border-t border-[var(--border-color)]">
        <div className="flex gap-2 mb-4 overflow-x-auto no-scrollbar pb-2">
          {[
            { id: 'visualize', label: 'Visualizer', icon: '🎨' },
            { id: 'solve', label: 'Step-by-Step Solver', icon: '🧠' },
            { id: 'formula', label: 'Formula Sheet', icon: 'π' },
            { id: 'viva', label: 'Viva Master', icon: '🎤' },
            { id: 'code', label: 'Code Mentor', icon: '💻' },
            { id: 'pinout', label: 'IC Pinout', icon: '🔌' },
          ].map(tool => (
            <button 
              key={tool.id} 
              onClick={() => handleActionClick(tool.id as ToolkitAction)}
              className="flex items-center gap-2 px-4 py-2.5 rounded-xl border border-[var(--border-color)] bg-[var(--input-bg)] text-[10px] font-black uppercase tracking-widest hover:border-blue-500/50 transition-all whitespace-nowrap"
            >
              <span>{tool.icon}</span> {tool.label}
            </button>
          ))}
        </div>

        <form onSubmit={handleSend} className="flex gap-3 max-w-5xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Describe your engineering query in detail..."
            className="flex-1 px-6 py-4 rounded-2xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-primary)] outline-none focus:border-blue-500/50 transition-all font-medium"
          />
          <button type="submit" disabled={isLoading || !input.trim()} className="px-10 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-blue-700 transition-all disabled:opacity-50 shadow-lg">
            Transmit
          </button>
        </form>
      </div>
    </div>
  );
};

