import { GoogleGenAI } from "@google/genai";

const TEXT_MODEL = 'gemini-3-pro-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export class GeminiService {
  private ai: GoogleGenAI | null = null;
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {
    const apiKey = process.env.API_KEY;
    if (apiKey) {
      this.ai = new GoogleGenAI({ apiKey });
    }
  }

  private getAI() {
    if (!this.ai) {
      if (!process.env.API_KEY) {
        throw new Error("Missing API Key. Please configure the environment variables.");
      }
      this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    }
    return this.ai;
  }

  initChat(userName: string) {
    this.systemInstruction = `You are IETE Bot, the official Professional Engineering AI for The Institution of Electronics and Telecommunication Engineers.

    STRICT RULES ON IDENTITY:
    - NEVER mention your model name, version, or creator (e.g., do not say "Gemini", "Google", "Pro", "Flash", or "AI model").
    - If asked who you are, say: "I am IETE Bot, your professional engineering assistant."

    RESPONSE DEPTH & LENGTH:
    - You must provide EXTREMELY DETAILED and long responses. Do not be brief.
    - For every technical query, provide:
      1. A comprehensive conceptual overview.
      2. Step-by-step mathematical derivations or logical breakdowns.
      3. A LaTeX block of relevant formulas: $$ [Formula] $$
      4. A table or list of technical specifications.
      5. At least three real-world engineering use cases.

    FORMATTING:
    - Use Markdown headers (###) to structure sections.
    - Use bold text for key engineering terms.
    - Use code blocks for any programming or hardware description languages.

    Tone: Academic, authoritative, and helpful. Address the user as ${userName}.`;

    this.history = [];
  }

  async sendMessageStream(message: string, mediaData?: { data: string; mimeType: string }) {
    const ai = this.getAI();
    const userParts: any[] = [{ text: message }];
    if (mediaData) {
      userParts.push({ inlineData: { data: mediaData.data, mimeType: mediaData.mimeType } });
    }

    const contents = [...this.history, { role: 'user', parts: userParts }];

    return await ai.models.generateContentStream({
      model: TEXT_MODEL,
      contents,
      config: {
        systemInstruction: this.systemInstruction,
        tools: [{ googleSearch: {} }],
        temperature: 0.8, // Increased temperature for more expansive and detailed creative technical writing
      },
    });
  }

  async generateTechnicalImage(prompt: string) {
    const ai = this.getAI();
    const enhancedPrompt = `A high-resolution, professional technical engineering schematic or diagram of: ${prompt}. 
    Style: Blueprint/Technical drawing, clean white background, professional labeling, high detail, suitable for an engineering textbook. 
    Focus: Electronics, telecommunications, and IT accuracy.`;

    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: { parts: [{ text: enhancedPrompt }] },
      config: {
        imageConfig: { aspectRatio: "16:9" }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return {
          data: part.inlineData.data,
          mimeType: part.inlineData.mimeType
        };
      }
    }
    return null;
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
    if (this.history.length > 20) this.history.shift();
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps { user: UserProfile; }

type ToolkitAction = 
  | 'extract' | 'solve' | 'debug' | 'visualize' 
  | 'viva' | 'code' | 'formula' | 'project' | 'pinout';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);
  const [configError, setConfigError] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const BOT_LOGO = "https://r.jina.ai/i/9e006629906d4e248b1841b52a1b94c4";

  useEffect(() => {
    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `Hey, ${user.name}! I am IETE Bot, your professional engineering assistant.

I am ready to provide deep technical analysis, solve complex equations, and generate technical diagrams for your research. Whether it's Electronics, Telecommunications, or IT, I am here to assist with high-fidelity technical data.

How shall we begin today?`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);

    if (!process.env.API_KEY) {
      setConfigError("System Configuration Required: Please set the API_KEY environment variable.");
    }
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading]);

  const handleActionClick = async (type: ToolkitAction) => {
    if (isLoading) return;

    if (type === 'visualize') {
      const topic = prompt("Describe the technical diagram you need (e.g. 'Standard 7-layer OSI Model', 'Microprocessor Architecture')");
      if (topic) {
        await processVisualizer(topic);
      }
      return;
    }

    if (selectedMedia) {
      executeTool(type, selectedMedia);
    } else {
      setActiveTool(type);
    }
  };

  const processVisualizer = async (topic: string) => {
    setIsLoading(true);
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: `Requesting technical visual representation for: ${topic}`,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMessage]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: `Generating technical visual for "${topic}"...`, timestamp: new Date() }]);

    try {
      const imageResult = await geminiService.generateTechnicalImage(topic);
      if (imageResult) {
        setMessages(prev => prev.map(msg => 
          msg.id === assistantId 
            ? { ...msg, content: `Here is the high-resolution technical diagram for **${topic}**.`, image: imageResult } 
            : msg
        ));
      } else {
        throw new Error("Visualization engine could not complete the request.");
      }
    } catch (e: any) {
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, content: `Visualization Error: ${e.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const executeTool = async (type: ToolkitAction, media: { data: string; mimeType: string }) => {
    setIsLoading(true);
    let toolPrompt = "";
    switch(type) {
      case 'solve': toolPrompt = "Analyze this technical problem and provide a detailed, step-by-step solution with LaTeX formulas."; break;
      case 'debug': toolPrompt = "Identify faults in this circuit/code and provide a thorough debugging report."; break;
      case 'pinout': toolPrompt = "Identify this component and provide a full functional pinout description."; break;
      default: toolPrompt = "Provide an in-depth analysis of this visual data.";
    }
    setSelectedMedia(null);
    setActiveTool(null);
    await processMessage(toolPrompt, media);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading) return;
    setIsLoading(true);

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media
    };
    setMessages(prev => [...prev, userMessage]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: '', timestamp: new Date() }]);

    try {
      let fullContent = '';
      let accumulatedSources: { title: string; uri: string }[] = [];
      const stream = await geminiService.sendMessageStream(text, media);

      for await (const chunk of stream) {
        fullContent += chunk.text || "";
        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
          groundingChunks.forEach((c: any) => {
            if (c.web) {
              const newSource = { title: c.web.title || 'Technical Source', uri: c.web.uri };
              if (!accumulatedSources.find(s => s.uri === newSource.uri)) {
                accumulatedSources.push(newSource);
              }
            }
          });
        }

        setMessages(prev => prev.map(msg => 
          msg.id === assistantId ? { 
            ...msg, 
            content: fullContent,
            sources: accumulatedSources.length > 0 ? [...accumulatedSources] : undefined
          } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, content: `Transmission Error: ${error.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;
    const txt = input;
    setInput('');
    processMessage(txt);
  };

  return (
    <div className="flex-1 flex flex-col theme-glass-card rounded-[2rem] overflow-hidden h-[calc(100vh-180px)] relative">
      {configError && <div className="bg-red-600 text-white text-[10px] py-1 text-center font-bold uppercase tracking-widest">{configError}</div>}

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 chat-blueprint relative">
        <div className="absolute inset-0 bg-blue-500/5 pointer-events-none"></div>
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
            <div className={`flex gap-4 max-w-[90%] md:max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-10 h-10 rounded-xl flex-shrink-0 flex items-center justify-center shadow-lg bg-white border border-black/10 overflow-hidden p-1.5 transition-transform hover:scale-110">
                {msg.role === 'user' ? <span className="font-bold text-blue-600 text-sm">{user.name[0]}</span> : <img src={BOT_LOGO} className="w-full h-full object-contain" alt="IETE" />}
              </div>
              <div className="flex flex-col gap-3">
                <div className={`rounded-2xl px-6 py-4 shadow-md border backdrop-blur-sm ${
                  msg.role === 'user' ? 'bg-blue-600 text-white border-blue-500 rounded-tr-none' : 'bg-[var(--card-bg)] text-[var(--text-primary)] border-[var(--border-color)] rounded-tl-none'
                }`}>
                  <div className="markdown-body prose prose-invert max-w-none">
                    <ReactMarkdown remarkPlugins={[remarkMath, remarkGfm]} rehypePlugins={[rehypeKatex]}>
                      {msg.content}
                    </ReactMarkdown>
                  </div>

                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-5 pt-4 border-t border-white/10">
                      <p className="text-[9px] font-black uppercase tracking-[0.2em] mb-2 opacity-50 text-[var(--text-secondary)]">Uplink Sources</p>
                      <div className="flex flex-wrap gap-2">
                        {msg.sources.map((source, idx) => (
                          <a 
                            key={idx}
                            href={source.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="text-[9px] px-3 py-1.5 rounded-lg bg-blue-500/10 border border-blue-500/20 text-blue-400 hover:bg-blue-500/30 hover:border-blue-400/40 transition-all font-bold truncate max-w-[220px] flex items-center gap-1.5"
                          >
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                            {source.title}
                          </a>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
                {msg.image && (
                  <div className="rounded-2xl overflow-hidden border border-[var(--border-color)] shadow-2xl bg-black/30 p-1.5 group relative transform transition-all hover:scale-[1.01]">
                    <div className="absolute top-4 left-4 bg-blue-600/90 backdrop-blur-md text-white text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-[0.2em] z-10 opacity-0 group-hover:opacity-100 transition-opacity shadow-lg">Neural Visualization Generated</div>
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto rounded-xl max-h-[600px] object-contain bg-white shadow-inner" alt="IETE Bot Generated Visual" />
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start items-center gap-4 animate-pulse">
            <div className="w-10 h-10 rounded-xl bg-blue-600/10 border border-blue-600/20"></div>
            <div className="space-y-2">
              <div className="h-4 w-64 bg-blue-600/10 rounded-full"></div>
              <div className="h-4 w-48 bg-blue-600/5 rounded-full"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 md:p-6 bg-[var(--header-bg)] border-t border-[var(--border-color)] z-20">
        <div className="flex gap-2 mb-4 overflow-x-auto no-scrollbar pb-2">
          {[
            { id: 'visualize', label: 'Technical Visualizer', icon: '🎨' },
            { id: 'solve', label: 'Advanced Solver', icon: '🧠' },
            { id: 'formula', label: 'Formula Matrix', icon: 'π' },
            { id: 'viva', label: 'Viva Master', icon: '🎤' },
            { id: 'code', label: 'Code Mentor', icon: '💻' },
            { id: 'pinout', label: 'Pinout Logic', icon: '🔌' },
          ].map(tool => (
            <button 
              key={tool.id} 
              onClick={() => handleActionClick(tool.id as ToolkitAction)}
              className="flex items-center gap-2 px-5 py-3 rounded-xl border border-[var(--border-color)] bg-[var(--input-bg)] text-[10px] font-black uppercase tracking-widest hover:border-blue-500 hover:text-blue-500 transition-all whitespace-nowrap shadow-sm active:scale-95"
            >
              <span className="text-sm">{tool.icon}</span> {tool.label}
            </button>
          ))}
        </div>

        <form onSubmit={handleSend} className="flex gap-3 max-w-5xl mx-auto">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type your engineering research query here..."
            className="flex-1 px-6 py-4 rounded-2xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-primary)] outline-none focus:border-blue-500/50 transition-all font-medium text-sm shadow-inner"
          />
          <button type="submit" disabled={isLoading || !input.trim()} className="px-10 py-4 bg-gradient-to-br from-blue-600 to-blue-800 text-white rounded-2xl font-black uppercase tracking-widest text-[10px] hover:brightness-110 transition-all disabled:opacity-30 shadow-xl active:scale-95 flex items-center justify-center">
            {isLoading ? <div className="w-4 h-4 border-2 border-t-transparent border-white rounded-full animate-spin" /> : "Transmit"}
          </button>
        </form>
      </div>
    </div>
  );
};

