                    <div className="absolute top-4 left-4 bg-blue-900/90 backdrop-blur-md text-white text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-[0.2em] z-10 opacity-0 group-hover:opacity-100 transition-opacity shadow-lg">Neural Visualization Generated</div>
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto rounded-xl max-h-[600px] object-contain bg-white shadow-inner" alt="IETE Bot Generated Visual" />
                  </div>
                )}
