          <button type="submit" disabled={isLoading || !input.trim()} className="px-10 py-4 bg-gradient-to-br from-blue-800 to-blue-950 text-white rounded-2xl font-black uppercase tracking-widest text-[10px] hover:brightness-110 transition-all disabled:opacity-30 shadow-xl active:scale-95 flex items-center justify-center">
            {isLoading ? <div className="w-4 h-4 border-2 border-t-transparent border-white rounded-full animate-spin" /> : "Transmit"}
