            if (c.web) {
              const newSource = { title: c.web.title || 'Technical Source', uri: c.web.uri };
              if (!accumulatedSources.find(s => s.uri === newSource.uri)) {
                accumulatedSources.push(newSource);
              }
            }
          });
        }

        setMessages(prev => prev.map(msg => 
          msg.id === assistantId ? { 
            ...msg, 
            content: fullContent,
            sources: accumulatedSources.length > 0 ? [...accumulatedSources] : undefined
          } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, content: `Transmission Error: ${error.message}` } : msg));
    } finally {
      setIsLoading(false);
