import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps { user: UserProfile; }

type ToolkitAction = 
  | 'extract' | 'solve' | 'debug' | 'visualize' 
  | 'viva' | 'code' | 'formula' | 'project' | 'pinout'
  | 'datasheet' | 'simulation' | 'research' | 'examprep' | 'units';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [activeTool, setActiveTool] = useState<ToolkitAction | null>(null);
  const [configError, setConfigError] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const BOT_LOGO = "https://jit.ac.in/assets/uploads/2022/12/IETE-logo.png";

  useEffect(() => {
    const initialMessage: Message = {
      id: 'initial',
      role: 'assistant',
      content: `Hey, ${user.name}! I am IETE Bot, your professional engineering assistant.

I am ready to provide deep technical analysis, solve complex equations, and generate technical diagrams for your research. Whether it's Electronics, Telecommunications, or IT, I am here to assist with high-fidelity technical data.

**You can now upload images of circuits, components, or code for extraction and analysis, or use the specialized engineering toolkit below.** How shall we begin today?`,
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);

    if (!process.env.API_KEY) {
      setConfigError("System Configuration Required: Please set the API_KEY environment variable.");
    }
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64Data = (reader.result as string).split(',')[1];
        setSelectedMedia({ data: base64Data, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleActionClick = async (type: ToolkitAction) => {
    if (isLoading) return;

    if (type === 'visualize') {
      const topic = prompt("Describe the technical diagram you need (e.g. 'Standard 7-layer OSI Model', 'Microprocessor Architecture')");
      if (topic) {
        await processVisualizer(topic);
      }
      return;
    }

    if (selectedMedia) {
      executeTool(type, selectedMedia);
    } else {
      setActiveTool(type);
      if (type === 'extract' || (type === 'debug' && !selectedMedia)) {
        // If it's a visual tool and no media is selected, trigger upload first
        if (type === 'debug') {
           const confirmUpload = window.confirm("Circuit Debug works best with a circuit diagram or PCB photo. Would you like to upload an image first?");
           if (confirmUpload) {
             fileInputRef.current?.click();
             return;
           }
        } else if (type === 'extract') {
          fileInputRef.current?.click();
          return;
        }
      }

      const userInput = prompt(`IETE Tool: ${type.toUpperCase()}\nPlease provide the details or subject for this analysis:`);
      if (userInput) {
        executeTool(type, undefined, userInput);
      }
    }
  };

  const processVisualizer = async (topic: string) => {
    setIsLoading(true);
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: `Requesting technical visual representation for: ${topic}`,
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMessage]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: `Generating technical visual for "${topic}"...`, timestamp: new Date() }]);

    try {
      const imageResult = await geminiService.generateTechnicalImage(topic);
      if (imageResult) {
        setMessages(prev => prev.map(msg => 
          msg.id === assistantId 
            ? { ...msg, content: `Here is the high-resolution technical diagram for **${topic}**.`, image: imageResult } 
            : msg
        ));
      } else {
        throw new Error("Visualization engine could not complete the request.");
      }
    } catch (e: any) {
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, content: `Visualization Error: ${e.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const executeTool = async (type: ToolkitAction, media?: { data: string; mimeType: string }, customText?: string) => {
    setIsLoading(true);
    let toolPrompt = "";
    const subject = customText || "";

    switch(type) {
      case 'extract': toolPrompt = `Analyze this image and extract all technical data, text, and component details into a structured report.`; break;
      case 'solve': toolPrompt = `Analyze the following technical problem and provide a detailed, step-by-step solution with LaTeX formulas: ${subject}`; break;
      case 'debug': toolPrompt = `Perform a comprehensive CIRCUIT DEBUG on this hardware design or description: ${subject}. Identify potential short circuits, impedance mismatches, power rail issues, or logical faults. Provide a prioritized fix list.`; break;
      case 'pinout': toolPrompt = `Identify this component and provide a full functional pinout description with electrical specifications: ${subject}`; break;
      case 'datasheet': toolPrompt = `Provide a comprehensive datasheet summary for: ${subject}. Include absolute maximum ratings, pin descriptions, and typical application circuits.`; break;
      case 'simulation': toolPrompt = `Write or debug a simulation script (Matlab/Python/LTSpice) for the following requirement: ${subject}`; break;
      case 'research': toolPrompt = `Act as a Research Assistant. Help me with IEEE paper structure, abstract drafting, or technical literature review for: ${subject}`; break;
      case 'examprep': toolPrompt = `Generate a set of high-difficulty GATE/IES level multiple-choice questions with deep technical explanations for: ${subject}`; break;
      case 'units': toolPrompt = `Perform precise engineering unit conversions and explain the physical constants involved for: ${subject}`; break;
      case 'viva': toolPrompt = `Simulate a technical viva voce for the project/topic: ${subject}. Ask me 5 challenging questions one by one.`; break;
      case 'code': toolPrompt = `Generate optimized, professional-grade code for: ${subject}`; break;
      case 'formula': toolPrompt = `List all governing equations and physical constants for the engineering domain: ${subject}`; break;
      case 'project': toolPrompt = `Provide a complete engineering project roadmap including BOM, circuit theory, and firmware logic for: ${subject}`; break;
      default: toolPrompt = `Provide an in-depth analysis for: ${subject}`;
    }

    setSelectedMedia(null);
    setActiveTool(null);
    await processMessage(toolPrompt, media);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }) => {
    if (isLoading) return;
    setIsLoading(true);

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: new Date(),
      image: media
    };
    setMessages(prev => [...prev, userMessage]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: '', timestamp: new Date() }]);

    try {
      let fullContent = '';
      let accumulatedSources: { title: string; uri: string }[] = [];
      const stream = await geminiService.sendMessageStream(text, media);

      for await (const chunk of stream) {
        fullContent += chunk.text || "";
        const groundingChunks = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (groundingChunks) {
          groundingChunks.forEach((c: any) => {
            if (c.web) {
              const newSource = { title: c.web.title || 'Technical Source', uri: c.web.uri };
              if (!accumulatedSources.find(s => s.uri === newSource.uri)) {
                accumulatedSources.push(newSource);
              }
            }
          });
        }

        setMessages(prev => prev.map(msg => 
          msg.id === assistantId ? { 
            ...msg, 
            content: fullContent,
            sources: accumulatedSources.length > 0 ? [...accumulatedSources] : undefined
          } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map(msg => msg.id === assistantId ? { ...msg, content: `Transmission Error: ${error.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading) return;
    const txt = input || (selectedMedia ? "Please analyze this image." : "");
    const media = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    processMessage(txt, media || undefined);
  };

  return (
    <div className="flex-1 flex flex-col theme-glass-card rounded-[2rem] overflow-hidden h-[calc(100vh-180px)] relative">
      {configError && <div className="bg-red-600 text-white text-[10px] py-1 text-center font-bold uppercase tracking-widest">{configError}</div>}

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 chat-blueprint relative">
        <div className="absolute inset-0 bg-blue-500/5 pointer-events-none"></div>
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2 duration-300`}>
            <div className={`flex gap-4 max-w-[90%] md:max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center shadow-lg bg-white border border-black/10 overflow-hidden p-0.5 transition-transform hover:scale-110">
                {msg.role === 'user' ? <span className="font-bold text-blue-900 text-sm">{user.name[0]}</span> : <img src={BOT_LOGO} className="w-full h-full object-contain" alt="IETE" />}
              </div>
              <div className="flex flex-col gap-3">
                <div className={`rounded-2xl px-6 py-4 shadow-md border backdrop-blur-sm ${
                  msg.role === 'user' ? 'bg-blue-900 text-white border-blue-800 rounded-tr-none' : 'bg-[var(--card-bg)] text-[var(--text-primary)] border-[var(--border-color)] rounded-tl-none'
                }`}>
                  <div className="markdown-body prose prose-invert max-w-none">
                    <ReactMarkdown remarkPlugins={[remarkMath, remarkGfm]} rehypePlugins={[rehypeKatex]}>
                      {msg.content}
                    </ReactMarkdown>
                  </div>

                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-5 pt-4 border-t border-white/10">
                      <p className="text-[9px] font-black uppercase tracking-[0.2em] mb-2 opacity-50 text-[var(--text-secondary)]">Uplink Sources</p>
                      <div className="flex flex-wrap gap-2">
                        {msg.sources.map((source, idx) => (
                          <a 
                            key={idx}
                            href={source.uri} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="text-[9px] px-3 py-1.5 rounded-lg bg-blue-500/10 border border-blue-500/20 text-blue-400 hover:bg-blue-500/30 hover:border-blue-400/40 transition-all font-bold truncate max-w-[220px] flex items-center gap-1.5"
                          >
                            <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"></path></svg>
                            {source.title}
                          </a>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
                {msg.image && (
                  <div className="rounded-2xl overflow-hidden border border-[var(--border-color)] shadow-2xl bg-black/30 p-1.5 group relative transform transition-all hover:scale-[1.01]">
                    <div className="absolute top-4 left-4 bg-blue-900/90 backdrop-blur-md text-white text-[8px] px-3 py-1 rounded-full font-black uppercase tracking-[0.2em] z-10 opacity-0 group-hover:opacity-100 transition-opacity shadow-lg">Component/Circuit Visualization</div>
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto rounded-xl max-h-[600px] object-contain bg-white shadow-inner" alt="IETE Bot Generated Visual" />
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start items-center gap-4 animate-pulse">
            <div className="w-10 h-10 rounded-full bg-blue-900/10 border border-blue-900/20"></div>
            <div className="space-y-2">
              <div className="h-4 w-64 bg-blue-900/10 rounded-full"></div>
              <div className="h-4 w-48 bg-blue-900/5 rounded-full"></div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 md:p-6 bg-[var(--header-bg)] border-t border-[var(--border-color)] z-20">
        {selectedMedia && (
          <div className="mb-4 animate-in slide-in-from-bottom-4 duration-300">
            <div className="relative inline-block group">
              <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-24 w-auto rounded-xl border-2 border-blue-500 shadow-xl" alt="Preview" />
              <button 
                onClick={() => setSelectedMedia(null)}
                className="absolute -top-2 -right-2 bg-red-600 text-white rounded-full p-1 shadow-lg hover:bg-red-700 transition-colors"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            </div>
          </div>
        )}

        <div className="flex gap-2 mb-4 overflow-x-auto no-scrollbar pb-2">
          {[
            { id: 'extract', label: 'Image Extract', icon: '🔍' },
            { id: 'debug', label: 'Circuit Debug', icon: '🛠️' },
            { id: 'visualize', label: 'Technical Visualizer', icon: '🎨' },
            { id: 'datasheet', label: 'Datasheet Sage', icon: '📑' },
            { id: 'simulation', label: 'Simulation Lab', icon: '🧪' },
            { id: 'solve', label: 'Advanced Solver', icon: '🧠' },
            { id: 'formula', label: 'Formula Matrix', icon: 'π' },
            { id: 'viva', label: 'Viva Master', icon: '🎤' },
            { id: 'research', label: 'Research Assist', icon: '📝' },
            { id: 'examprep', label: 'Exam Prep (GATE)', icon: '📚' },
            { id: 'units', label: 'Unit Converter', icon: '⚖️' },
            { id: 'code', label: 'Code Mentor', icon: '💻' },
            { id: 'pinout', label: 'Pinout Logic', icon: '🔌' },
          ].map(tool => (
            <button 
              key={tool.id} 
              onClick={() => handleActionClick(tool.id as ToolkitAction)}
              className="flex items-center gap-2 px-5 py-3 rounded-xl border border-[var(--border-color)] bg-[var(--input-bg)] text-[10px] font-black uppercase tracking-widest hover:border-blue-900 hover:text-blue-900 transition-all whitespace-nowrap shadow-sm active:scale-95 group"
            >
              <span className="text-sm transition-transform group-hover:scale-125">{tool.icon}</span> {tool.label}
            </button>
          ))}
        </div>

        <form onSubmit={handleSend} className="flex gap-3 max-w-5xl mx-auto items-center">
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileChange}
          />
          <button 
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="p-4 rounded-2xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-secondary)] hover:text-blue-500 hover:border-blue-500 transition-all shadow-inner"
            title="Upload Technical Image"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
          </button>

          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder={selectedMedia ? "Add a prompt or click Transmit to extract..." : "Type your engineering research query here..."}
            className="flex-1 px-6 py-4 rounded-2xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-primary)] outline-none focus:border-blue-900/50 transition-all font-medium text-sm shadow-inner"
          />

          <button type="submit" disabled={isLoading || (!input.trim() && !selectedMedia)} className="px-10 py-4 bg-gradient-to-br from-blue-800 to-blue-950 text-white rounded-2xl font-black uppercase tracking-widest text-[10px] hover:brightness-110 transition-all disabled:opacity-30 shadow-xl active:scale-95 flex items-center justify-center min-w-[120px]">
            {isLoading ? <div className="w-4 h-4 border-2 border-t-transparent border-white rounded-full animate-spin" /> : "Transmit"}
          </button>
        </form>
      </div>
    </div>
  );
};

