      default: toolPrompt = `${type.toUpperCase()} Analysis: ${subject}`;
    }

    setSelectedMedia(null);
    setInput('');
    await processMessage(toolPrompt, media, useSearch);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }, useSearch: boolean = false) => {
    if (isLoading || isTyping) return;
    setIsLoading(true);

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: text, timestamp: new Date(), image: media };
    setMessages(prev => [...prev, userMsg]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: '', timestamp: new Date() }]);

    try {
      let fullContent = '';
      const stream = await geminiService.sendMessageStream(text, media, useSearch);

      for await (const chunk of stream) {
        fullContent += chunk.text || "";
        setMessages(prev => prev.map((msg): Message => 
          msg.id === assistantId ? { 
            ...msg, 
            content: fullContent,
            sources: chunk.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => ({
              title: c.web?.title || 'Resource',
              uri: c.web?.uri
            })).filter((s: any) => s.uri)
          } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map((msg): Message => msg.id === assistantId ? { ...msg, content: `Transmission Fail: ${error.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading || isTyping) return;
    const txt = input;
    const media = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    processMessage(txt, media || undefined);
  };

  return (
    <div className="flex-1 flex flex-col theme-glass-card rounded-[2rem] overflow-hidden h-[calc(100vh-180px)] relative">
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 chat-blueprint relative">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-4 max-w-[90%] md:max-w-[80%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center bg-white border border-black/10 overflow-hidden p-0.5">
                {msg.role === 'user' ? <span className="font-bold text-blue-900">{user.name[0]}</span> : <img src={BOT_LOGO} className="w-full h-full object-contain" alt="IETE" />}
              </div>
              <div className="flex flex-col gap-2">
                <div className={`rounded-2xl px-6 py-4 shadow-md border ${msg.role === 'user' ? 'bg-blue-900 text-white' : 'bg-[var(--card-bg)] text-[var(--text-primary)] border-[var(--border-color)]'}`}>
                  <div className="markdown-body prose prose-invert max-w-none">
                    <ReactMarkdown remarkPlugins={[remarkMath, remarkGfm]} rehypePlugins={[rehypeKatex]}>{msg.content}</ReactMarkdown>
                  </div>
                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-4 pt-3 border-t border-white/10 flex flex-wrap gap-2">
                      {msg.sources.map((s, i) => <a key={i} href={s.uri} target="_blank" className="text-[8px] bg-blue-500/10 px-2 py-1 rounded text-blue-400 font-bold">{s.title}</a>)}
                    </div>
                  )}
                </div>
                {msg.image && (
                  <div className="rounded-xl border border-[var(--border-color)] overflow-hidden bg-white/5 p-1">
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-[400px] object-contain rounded-lg" alt="Diagram" />
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="p-4 md:p-6 bg-[var(--header-bg)] border-t border-[var(--border-color)]">
        <div className="flex gap-2 mb-4 overflow-x-auto no-scrollbar">
          {[
            { id: 'extract', label: 'Extract', icon: '🔍' },
            { id: 'debug', label: 'Debug', icon: '🛠️' },
            { id: 'research', label: 'Research (Web)', icon: '🌐' },
            { id: 'solve', label: 'Solve', icon: '🧠' },
            { id: 'examprep', label: 'GATE Prep', icon: '📚' },
          ].map(t => (
            <button key={t.id} onClick={() => handleActionClick(t.id as ToolkitAction)} className="flex items-center gap-2 px-4 py-2 bg-[var(--input-bg)] rounded-xl border border-[var(--border-color)] text-[9px] font-black uppercase tracking-widest hover:border-blue-500 transition-all shadow-sm">
              <span>{t.icon}</span> {t.label}
            </button>
          ))}
        </div>

        <form onSubmit={handleSend} className="flex gap-2">
          <input
            type="text" value={input} onChange={(e) => setInput(e.target.value)}
            placeholder="Technical query..."
            className="flex-1 px-5 py-3 rounded-xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-primary)] outline-none focus:border-blue-500/50"
            disabled={isLoading || isTyping}
          />
          <button type="submit" disabled={isLoading || isTyping || !input.trim()} className="px-8 py-3 bg-blue-900 text-white rounded-xl font-black uppercase text-[10px] tracking-widest hover:brightness-110 disabled:opacity-20 shadow-lg transition-all">
            {isLoading ? "Transmitting..." : "Transmit"}
          </button>
        </form>
      </div>
    </div>
  );
};

