import { GoogleGenAI } from "@google/genai";

const TEXT_MODEL = 'gemini-flash-lite-latest';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export class GeminiService {
  private ai: GoogleGenAI | null = null;
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {
    const apiKey = process.env.API_KEY;
    if (apiKey) {
      this.ai = new GoogleGenAI({ apiKey });
    }
  }

  private getAI() {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("Missing API Key. Please configure the environment variables.");
    }
    return new GoogleGenAI({ apiKey });
  }

  initChat(userName: string) {
    this.systemInstruction = `You are IETE Bot, the official Professional Engineering AI for The Institution of Electronics and Telecommunication Engineers.

    STRICT RULES ON IDENTITY:
    - NEVER mention model names or versions.
    - Say: "I am IETE Bot, your professional engineering assistant."

    TECHNICAL OUTPUT:
    - Use LaTeX for ALL formulas: $$ [Formula] $$.
    - Keep responses concise but mathematically dense.
    - Identify as IETE Bot for ${userName}.`;

    this.history = [];
  }

  async sendMessageStream(message: string, mediaData?: { data: string; mimeType: string }, useSearch: boolean = false) {
    const ai = this.getAI();
    const userParts: any[] = [{ text: message }];
    if (mediaData) {
      userParts.push({ inlineData: { data: mediaData.data, mimeType: mediaData.mimeType } });
    }

    const contents = [...this.history, { role: 'user', parts: userParts }];

    return await ai.models.generateContentStream({
      model: TEXT_MODEL,
      contents,
      config: {
        systemInstruction: this.systemInstruction,
        // Only trigger tools if explicitly requested to save API quota
        tools: useSearch ? [{ googleSearch: {} }] : undefined,
        temperature: 0.7,
        maxOutputTokens: 2048,
      },
    });
  }

  async generateTechnicalImage(prompt: string) {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: { parts: [{ text: `Professional engineering blueprint/schematic of: ${prompt}` }] },
      config: {
        imageConfig: { aspectRatio: "16:9" }
      }
    });

    if (!response.candidates || response.candidates.length === 0) return null;
    const content = response.candidates[0].content;
    if (!content || !content.parts) return null;

    for (const part of content.parts) {
      if (part.inlineData?.data && part.inlineData?.mimeType) {
        return {
          data: part.inlineData.data as string,
          mimeType: part.inlineData.mimeType as string
        };
      }
    }
    return null;
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
    // Reduced history to 10 to prevent "API Limit/Context Window" errors with long messages
    if (this.history.length > 10) this.history.shift();
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps { user: UserProfile; }

type ToolkitAction = 
  | 'extract' | 'solve' | 'debug' | 'visualize' 
  | 'viva' | 'code' | 'formula' | 'project' | 'pinout'
  | 'datasheet' | 'simulation' | 'research' | 'examprep' | 'units'
  | 'boolean' | 'hdl' | 'transform' | 'analog' | 'modulation' | 'rf';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [configError, setConfigError] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const BOT_LOGO = "https://jit.ac.in/assets/uploads/2022/12/IETE-logo.png";

  useEffect(() => {
    const getGreeting = () => {
      const hour = new Date().getHours();
      if (hour >= 5 && hour < 12) return "Good morning";
      if (hour >= 12 && hour < 17) return "Good afternoon";
      if (hour >= 17 && hour < 21) return "Good evening";
      return "Hello";
    };

    const initialId = 'initial-' + Date.now();
    const initialMessage: Message = {
      id: initialId,
      role: 'assistant',
      content: '', 
      timestamp: new Date()
    };
    setMessages([initialMessage]);
    geminiService.initChat(user.name);

    if (!process.env.API_KEY) {
      setConfigError("System Configuration Required: API_KEY is missing.");
    }

    const welcomeText = `${getGreeting()}, ${user.name}! I am IETE Bot. Your ECE technical terminal is ready. Use the toolkit below for specialized engineering analysis.`;

    let currentText = "";
    const words = welcomeText.split(" ");
    let i = 0;

    setIsTyping(true);
    const interval = setInterval(() => {
      if (i < words.length) {
        currentText += (i === 0 ? "" : " ") + words[i];
        setMessages((prev: Message[]): Message[] => 
          prev.map((m: Message): Message => m.id === initialId ? { ...m, content: currentText } : m)
        );
        i++;
      } else {
        clearInterval(interval);
        setIsTyping(false);
      }
    }, 15);

    return () => clearInterval(interval);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'auto' });
    }
  }, [messages, isLoading, isTyping]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        const base64Data = result.split(',')[1];
        setSelectedMedia({ data: base64Data, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleActionClick = async (type: ToolkitAction) => {
    if (isLoading || isTyping) return;
    let context = input.trim();

    if (type === 'visualize') {
      const topic = context || prompt("Describe the circuit or block diagram to visualize:");
      if (topic) await processVisualizer(topic);
      return;
    }

    if ((type === 'extract' || type === 'debug') && !selectedMedia && !context) {
       fileInputRef.current?.click();
       return;
    }

    if (!context && !selectedMedia) {
       context = prompt(`Enter subject/expression for ${type.toUpperCase()}:`) || "";
       if (!context) return;
    }

    executeTool(type, selectedMedia || undefined, context);
  };

  const processVisualizer = async (topic: string) => {
    setIsLoading(true);
    const assistantId = (Date.now() + 1).toString();
    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: `Requesting Technical Schematic: ${topic}`, timestamp: new Date() };
    const loadingMsg: Message = { id: assistantId, role: 'assistant', content: `Generating technical blueprint for **${topic}**...`, timestamp: new Date() };

    setMessages((prev: Message[]): Message[] => [...prev, userMsg, loadingMsg]);

    try {
      const result = await geminiService.generateTechnicalImage(topic);
      if (result) {
        setMessages((prev: Message[]): Message[] => prev.map((msg: Message): Message => 
          msg.id === assistantId ? { 
            ...msg, 
            content: `Schematic for **${topic}** rendered successfully.`, 
            image: { 
              data: result.data, 
              mimeType: result.mimeType 
            } 
          } : msg
        ));
      } else {
        throw new Error("Schematic generation timed out.");
      }
    } catch (e: any) {
      setMessages((prev: Message[]): Message[] => prev.map((msg: Message): Message => 
        msg.id === assistantId ? { ...msg, content: `Visualization error: ${e.message}` } : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const executeTool = async (type: ToolkitAction, media?: { data: string; mimeType: string }, customText?: string) => {
    let toolPrompt = "";
    const subject = customText || "";
    const useSearch = type === 'research';

    switch(type) {
      case 'extract': toolPrompt = `Perform technical extraction from source: ${subject}`; break;
      case 'debug': toolPrompt = `Analyze this electronics/communication problem for faults: ${subject}`; break;
      case 'research': toolPrompt = `Perform IEEE research documentation for: ${subject}`; break;
      case 'solve': toolPrompt = `Provide a step-by-step mathematical engineering solution for: ${subject}`; break;
      case 'formula': toolPrompt = `Provide a comprehensive equation matrix for: ${subject}`; break;
      case 'boolean': toolPrompt = `Simplify this boolean expression, generate the truth table, and provide K-Map reduction for: ${subject}`; break;
      case 'hdl': toolPrompt = `Synthesize professional Verilog/VHDL code and testbench for the digital logic: ${subject}`; break;
      case 'transform': toolPrompt = `Perform Signals & Systems analysis (Laplace, Z-Transform, or Fourier) for the system: ${subject}`; break;
      case 'analog': toolPrompt = `Analyze this Analog Circuit (BJT, MOSFET, or Op-Amp) for biasing, gain, and frequency response: ${subject}`; break;
      case 'modulation': toolPrompt = `Explain and calculate parameters for Communication Modulation (AM, FM, QAM, PCM) for: ${subject}`; break;
      case 'rf': toolPrompt = `Perform Microwave/RF analysis, transmission line calculations, or Smith Chart analysis for: ${subject}`; break;
      case 'examprep': toolPrompt = `Generate a GATE/IES level technical practice module for: ${subject}`; break;
      case 'code': toolPrompt = `Generate optimized Embedded C code (8051/ARM/AVR) for: ${subject}`; break;
      default: toolPrompt = `${type.toUpperCase()} Engineering Analysis: ${subject}`;
    }

    setSelectedMedia(null);
    setInput('');
    await processMessage(toolPrompt, media, useSearch);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }, useSearch: boolean = false) => {
    if (isLoading || isTyping) return;
    setIsLoading(true);

    const userMsg: Message = { 
      id: Date.now().toString(), 
      role: 'user', 
      content: text, 
      timestamp: new Date(), 
      image: media ? { data: media.data, mimeType: media.mimeType } : undefined 
    };
    setMessages((prev: Message[]): Message[] => [...prev, userMsg]);

    const assistantId = (Date.now() + 1).toString();
    setMessages((prev: Message[]): Message[] => [...prev, { id: assistantId, role: 'assistant', content: '', timestamp: new Date() }]);

    try {
      let fullContent = '';
      const stream = await geminiService.sendMessageStream(text, media, useSearch);

      for await (const chunk of stream) {
        fullContent += chunk.text || "";
        setMessages((prev: Message[]): Message[] => prev.map((msg: Message): Message => 
          msg.id === assistantId ? { 
            ...msg, 
            content: fullContent,
            sources: chunk.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((c: any) => ({
              title: c.web?.title || 'Resource',
              uri: c.web?.uri || ''
            })).filter((s: any) => s.uri)
          } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages((prev: Message[]): Message[] => prev.map((msg: Message): Message => 
        msg.id === assistantId ? { ...msg, content: `Error: ${error.message}` } : msg
      ));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading || isTyping) return;
    const txt = input;
    const media = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    processMessage(txt, media || undefined);
  };

  return (
    <div className="flex-1 flex flex-col theme-glass-card rounded-[2rem] overflow-hidden h-[calc(100vh-180px)] relative">
      {configError && <div className="bg-red-600/90 backdrop-blur text-white text-[10px] py-1 text-center font-bold absolute top-0 left-0 right-0 z-50">{configError}</div>}

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 chat-blueprint relative">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-4 max-w-[90%] md:max-w-[80%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center bg-white border border-black/10 overflow-hidden p-0.5 shadow-sm">
                {msg.role === 'user' ? <span className="font-bold text-blue-900">{user.name[0]}</span> : <img src={BOT_LOGO} className="w-full h-full object-contain" alt="IETE" />}
              </div>
              <div className="flex flex-col gap-2">
                <div className={`rounded-2xl px-6 py-4 shadow-md border ${msg.role === 'user' ? 'bg-blue-900 text-white' : 'bg-[var(--card-bg)] text-[var(--text-primary)] border-[var(--border-color)]'}`}>
                  <div className="markdown-body prose prose-invert max-w-none">
                    <ReactMarkdown remarkPlugins={[remarkMath, remarkGfm]} rehypePlugins={[rehypeKatex]}>{msg.content}</ReactMarkdown>
                  </div>
                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-4 pt-3 border-t border-white/10 flex flex-wrap gap-2">
                      {msg.sources.map((s, i) => <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[8px] bg-blue-500/10 px-2 py-1 rounded text-blue-400 font-bold hover:bg-blue-500/20 transition-colors">{s.title}</a>)}
                    </div>
                  )}
                </div>
                {msg.image && (
                  <div className="rounded-xl border border-[var(--border-color)] overflow-hidden bg-white/5 p-1 shadow-lg">
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-[400px] object-contain rounded-lg" alt="Technical visual" />
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="p-4 md:p-6 bg-[var(--header-bg)] border-t border-[var(--border-color)]">
        {selectedMedia && (
          <div className="mb-4 flex items-center gap-2 animate-in slide-in-from-left-2">
            <div className="relative group">
              <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-16 w-16 rounded-lg object-cover border-2 border-blue-500 shadow-lg" alt="Preview" />
