            { id: 'boolean', label: 'Boolean/K-Map', icon: '🔢' },
            { id: 'hdl', label: 'HDL/Verilog', icon: '⚡' },
            { id: 'transform', label: 'Signal Transform', icon: '📈' },
            { id: 'analog', label: 'Analog Pro', icon: '🔌' },
