import { GoogleGenAI } from "@google/genai";

// Model Definitions
const FAST_MODEL = 'gemini-2.5-flash-lite-latest';
const PRO_MODEL = 'gemini-3-pro-preview';
const SEARCH_MODEL = 'gemini-3-flash-preview';
const IMAGE_PRO_MODEL = 'gemini-3-pro-image-preview';

export class GeminiService {
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {}

  private getAI() {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("Missing API_KEY. Ensure it is set in Vercel/Environment Variables.");
    }
    return new GoogleGenAI({ apiKey });
  }

  initChat(userName: string) {
    this.systemInstruction = `Role: IETE Bot (Official Engineering Terminal).
User: ${userName}.
Domain: ECE, Telecommunication, IT, and Allied Engineering.

Response Protocol:
1. Use LaTeX for ALL math/formulas: $$ [Formula] $$.
2. For "Step-by-Step", use numbered lists with clear physical justifications.
3. For "Direct Answer", provide only the core fact/value (no intro/outro).
4. Strictly follow IEEE standards and GATE syllabus.
5. Identify as IETE Bot; never mention Google or specific LLM names.`;

    this.history = [];
  }

  async sendMessageStream(
    message: string, 
    mediaData?: { data: string; mimeType: string }, 
    options: { useSearch?: boolean; useThinking?: boolean; forcePro?: boolean } = {}
  ) {
    const ai = this.getAI();
    const userParts: any[] = [{ text: message }];

    if (mediaData?.data && mediaData?.mimeType) {
      userParts.push({ 
        inlineData: { 
          data: mediaData.data, 
          mimeType: mediaData.mimeType 
        } 
      });
    }

    const contents = [...this.history, { role: 'user', parts: userParts }];

    // Select Model based on task
    let modelName = FAST_MODEL;
    if (options.useSearch) modelName = SEARCH_MODEL;
    else if (options.useThinking || options.forcePro || mediaData) modelName = PRO_MODEL;

    const config: any = {
      systemInstruction: this.systemInstruction,
      tools: options.useSearch ? [{ googleSearch: {} }] : undefined,
      temperature: options.useThinking ? 0.7 : 0.15,
    };

    // Configure Thinking Mode
    if (options.useThinking && modelName === PRO_MODEL) {
      config.thinkingConfig = { thinkingBudget: 32768 };
    }

    return await ai.models.generateContentStream({
      model: modelName,
      contents,
      config,
    });
  }

  async generateHighResImage(prompt: string, size: '1K' | '2K' | '4K' = '1K') {
    const ai = this.getAI();
    try {
      const response = await ai.models.generateContent({
        model: IMAGE_PRO_MODEL,
        contents: { 
          parts: [{ text: `Professional technical schematic blueprint of: ${prompt}. White background, IEEE standard symbols, high contrast, engineering grade labels.` }] 
        },
        config: {
          imageConfig: { 
            aspectRatio: "16:9",
            imageSize: size
          }
        }
      });

      const parts = response.candidates?.[0]?.content?.parts;
      if (parts) {
        for (const part of parts) {
          if (part.inlineData?.data) {
            return {
              data: part.inlineData.data as string,
              mimeType: part.inlineData.mimeType || 'image/png'
            };
          }
        }
      }
    } catch (e) {
      console.error("Pro Visualizer failed:", e);
    }
    return null;
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
    if (this.history.length > 10) this.history.shift();
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps { user: UserProfile; }

type ToolkitAction = 
  | 'extract' | 'solve' | 'debug' | 'visualize' 
  | 'viva' | 'code' | 'formula' | 'project' | 'pinout'
  | 'datasheet' | 'simulation' | 'research' | 'examprep' 
  | 'boolean' | 'hdl' | 'transform' | 'analog' | 'modulation' 
  | 'direct' | 'step_by_step' | 'control_sys' | 'gate_pyq';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [isThinkingMode, setIsThinkingMode] = useState(false);
  const [imageRes, setImageRes] = useState<'1K' | '2K' | '4K'>('1K');
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);
  const [configError, setConfigError] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const BOT_LOGO = "https://jit.ac.in/assets/uploads/2022/12/IETE-logo.png";

  useEffect(() => {
    const getGreeting = () => {
      const h = new Date().getHours();
      return h < 12 ? "Good morning" : h < 17 ? "Good afternoon" : "Good evening";
    };

    const initialId = 'init-' + Date.now();
    setMessages([{ id: initialId, role: 'assistant', content: '', timestamp: new Date() }]);
    geminiService.initChat(user.name);

    if (!process.env.API_KEY) {
      setConfigError("API_KEY MISSING: Ensure it is set in environment.");
    }

    const welcome = `${getGreeting()}, ${user.name}, enjoy your session.`;
    let current = "";
    const words = welcome.split(" ");
    let i = 0;

    setIsTyping(true);
    const interval = setInterval(() => {
      if (i < words.length) {
        current += (i === 0 ? "" : " ") + words[i];
        setMessages(prev => prev.map(m => m.id === initialId ? { ...m, content: current } : m));
        i++;
      } else {
        clearInterval(interval);
        setIsTyping(false);
      }
    }, 15);

    return () => clearInterval(interval);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading, isTyping]);

  const handleActionClick = async (type: ToolkitAction) => {
    if (isLoading || isTyping) return;
    let context = input.trim();

    if (type === 'visualize') {
      const topic = context || prompt("Enter Schematic Subject:");
      if (topic) await processVisualizer(topic);
      return;
    }

    if ((type === 'extract' || type === 'debug') && !selectedMedia) {
       fileInputRef.current?.click();
       return;
    }

    if (!context && !selectedMedia) {
       context = prompt(`${type.replace('_', ' ').toUpperCase()} context:`) || "";
       if (!context) return;
    }

    executeTool(type, selectedMedia || undefined, context);
  };

  const processVisualizer = async (topic: string) => {
    setIsLoading(true);
    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, 
      { id: Date.now().toString(), role: 'user', content: `Requesting ${imageRes} Schematic: ${topic}`, timestamp: new Date() },
      { id: assistantId, role: 'assistant', content: `Synthesizing ${imageRes} institutional blueprint...`, timestamp: new Date() }
    ]);

    try {
      const result = await geminiService.generateHighResImage(topic, imageRes);
      if (result) {
        setMessages(prev => prev.map((msg: Message): Message => msg.id === assistantId ? { 
          ...msg, content: `High-resolution (${imageRes}) schematic of **${topic}** compiled successfully.`, 
          image: { data: result.data, mimeType: result.mimeType } 
        } : msg));
      }
    } catch (e: any) {
      setMessages(prev => prev.map((msg: Message): Message => msg.id === assistantId ? { ...msg, content: `Render Error: ${e.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const executeTool = async (type: ToolkitAction, media?: { data: string; mimeType: string }, customText?: string) => {
    let promptText = "";
    const subject = customText || "";
    const useSearch = ['research', 'datasheet', 'gate_pyq'].includes(type);

    switch(type) {
      case 'direct': promptText = `Provide a concise engineering answer for: ${subject}`; break;
      case 'step_by_step': promptText = `Solve ${subject} with clear mathematical steps and physical justifications.`; break;
      case 'debug': promptText = `Analyze this image/description for circuit errors or design flaws: ${subject}`; break;
      case 'extract': promptText = `Extract all text and technical data from this source: ${subject}. Format as IEEE table.`; break;
      case 'boolean': promptText = `Minimize the logic expression: ${subject}. Provide K-Map and Truth Table.`; break;
      case 'control_sys': promptText = `Find Transfer Function, Root Locus, and Stability for: ${subject}`; break;
      case 'gate_pyq': promptText = `Search and solve GATE ECE Previous Year Question for: ${subject}`; break;
      default: promptText = `Engineering Analysis: ${subject}`;
    }

    setSelectedMedia(null);
    setInput('');
    await processMessage(promptText, media, useSearch);
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }, useSearch: boolean = false) => {
    if (isLoading || isTyping) return;
    setIsLoading(true);

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: text, timestamp: new Date(), image: media };
    setMessages(prev => [...prev, userMsg]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: '', timestamp: new Date() }]);

    try {
      let fullContent = '';
      const stream = await geminiService.sendMessageStream(text, media, { 
        useSearch, 
        useThinking: isThinkingMode,
        forcePro: !!media // Use Pro model for vision
      });

      for await (const chunk of stream) {
        fullContent += chunk.text || "";
        const grounding = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        const newSources = grounding?.map((c: any) => ({
          title: c.web?.title || 'Tech Link',
          uri: c.web?.uri || ''
        })).filter((s: any) => s.uri);

        setMessages(prev => prev.map((msg: Message): Message => 
          msg.id === assistantId ? { 
            ...msg, 
            content: fullContent,
            sources: newSources?.length ? newSources : msg.sources
          } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map((msg: Message): Message => msg.id === assistantId ? { ...msg, content: `Processing Failure: ${error.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex-1 flex flex-col theme-glass-card rounded-[2rem] overflow-hidden h-[calc(100vh-180px)] relative">
      {configError && <div className="bg-red-600/90 text-white text-[9px] py-1 text-center font-bold absolute top-0 w-full z-50 animate-pulse">{configError}</div>}

      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 chat-blueprint relative">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[92%] md:max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center bg-white border border-black/10 shadow-sm overflow-hidden p-0.5">
                {msg.role === 'user' ? <span className="font-black text-blue-900 text-sm uppercase">{user.name[0]}</span> : <img src={BOT_LOGO} className="w-full h-full object-contain" alt="IETE" />}
              </div>
              <div className="flex flex-col gap-2">
                <div className={`rounded-2xl px-5 py-4 shadow-md border backdrop-blur-md transition-all ${msg.role === 'user' ? 'bg-blue-950 text-white border-blue-900' : 'bg-[var(--card-bg)] text-[var(--text-primary)] border-[var(--border-color)]'}`}>
                  <div className="markdown-body prose prose-invert max-w-none text-sm leading-relaxed">
                    <ReactMarkdown remarkPlugins={[remarkMath, remarkGfm]} rehypePlugins={[rehypeKatex]}>{msg.content}</ReactMarkdown>
                  </div>
                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-4 pt-3 border-t border-white/10 flex flex-wrap gap-2">
                      {msg.sources.map((s, i) => <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[8px] bg-blue-500/10 px-2 py-1 rounded text-blue-400 font-bold hover:brightness-125 transition-all">{s.title}</a>)}
                    </div>
                  )}
                </div>
                {msg.image && (
                  <div className="rounded-xl border border-[var(--border-color)] overflow-hidden bg-white/5 p-1 shadow-2xl">
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-[500px] object-contain rounded-lg" alt="Schematic" />
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="p-4 md:p-6 bg-[var(--header-bg)] border-t border-[var(--border-color)] z-20">
        <div className="flex flex-col gap-3 mb-4">
          <div className="flex items-center justify-between gap-4">
            <div className="flex items-center gap-2 overflow-x-auto no-scrollbar pb-1">
              <span className="text-[9px] font-black bg-blue-900 text-white px-2 py-1 rounded-sm uppercase">Power Kit</span>
              {[
                { id: 'direct', label: 'Direct Ans', icon: '🎯' },
                { id: 'step_by_step', label: 'Step-by-Step', icon: '🔢' },
                { id: 'extract', label: 'BOM Extract', icon: '📄' },
                { id: 'debug', label: 'Circuit Debug', icon: '🛠️' },
                { id: 'boolean', label: 'Logic/K-Map', icon: '🧮' },
                { id: 'transform', label: 'Transforms', icon: '📈' },
                { id: 'gate_pyq', label: 'GATE PYQ', icon: '🎓' },
                { id: 'visualize', label: 'Schematic Gen', icon: '🎨' },
              ].map(t => (
                <button key={t.id} onClick={() => handleActionClick(t.id as ToolkitAction)} className="flex items-center gap-2 px-3 py-2 bg-[var(--input-bg)] rounded-xl border border-[var(--border-color)] text-[9px] font-black uppercase tracking-widest hover:border-blue-500 transition-all shadow-sm whitespace-nowrap active:scale-95">
                  <span>{t.icon}</span> {t.label}
                </button>
              ))}
            </div>

            <div className="flex items-center gap-3 border-l border-[var(--border-color)] pl-4 flex-shrink-0">
               <div className="flex flex-col">
                <span className="text-[8px] font-bold text-[var(--text-secondary)] uppercase">Res</span>
                <select 
                  value={imageRes} 
                  onChange={(e) => setImageRes(e.target.value as any)}
                  className="bg-transparent text-[10px] font-black text-blue-500 outline-none"
                >
                  <option value="1K">1K</option>
                  <option value="2K">2K</option>
                  <option value="4K">4K</option>
                </select>
              </div>
              <button 
                onClick={() => setIsThinkingMode(!isThinkingMode)}
                className={`flex items-center gap-2 px-3 py-2 rounded-xl border transition-all ${isThinkingMode ? 'bg-blue-900 border-blue-700 text-white' : 'bg-[var(--input-bg)] border-[var(--border-color)] text-[var(--text-secondary)]'}`}
              >
                <span className="text-[10px] font-black uppercase tracking-tighter">🧠 Deep Think</span>
              </button>
            </div>
          </div>
        </div>

        {selectedMedia && (
          <div className="mb-4 flex items-center gap-3 p-3 bg-blue-900/10 rounded-2xl border border-blue-900/30">
            <div className="relative">
              <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-16 w-16 rounded-xl object-cover border-2 border-blue-500 shadow-lg" alt="Input" />
              <button onClick={() => setSelectedMedia(null)} className="absolute -top-2 -right-2 bg-red-600 text-white rounded-full p-1.5 shadow-xl">
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            </div>
            <div className="flex flex-col">
              <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Vision Link Engaged</p>
              <p className="text-[9px] text-[var(--text-secondary)]">Analyzing image with Gemini 3 Pro...</p>
            </div>
          </div>
        )}

        <form onSubmit={handleSend} className="flex gap-3 max-w-6xl mx-auto">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
            const file = e.target.files?.[0];
            if (file) {
              const reader = new FileReader();
              reader.onloadend = () => {
                const b64 = (reader.result as string).split(',')[1];
                setSelectedMedia({ data: b64, mimeType: file.type });
              };
              reader.readAsDataURL(file);
            }
          }} />
          <button 
            type="button" 
            onClick={() => fileInputRef.current?.click()} 
            className="p-4 rounded-2xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-secondary)] hover:text-blue-500 transition-all shadow-inner"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>
          <input
            type="text" value={input} onChange={(e) => setInput(e.target.value.slice(0, 4000))}
            placeholder={isThinkingMode ? "Neural thinking enabled..." : "Input technical query..."}
            className="flex-1 px-6 py-4 rounded-2xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-primary)] outline-none focus:border-blue-900/50 text-sm transition-all shadow-inner"
            disabled={isLoading || isTyping}
