            className="flex-1 px-8 py-5 rounded-3xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-primary)] outline-none focus:border-blue-900/50 text-sm transition-all shadow-inner placeholder:text-white/20"
            disabled={isLoading || isTyping}
          />
          <button 
            type="submit" 
            disabled={isLoading || isTyping || (!input.trim() && !selectedMedia)} 
            className="px-12 py-5 bg-gradient-to-br from-blue-700 to-blue-950 text-white rounded-3xl font-black uppercase text-[12px] tracking-[0.3em] shadow-2xl hover:brightness-125 hover:shadow-blue-500/20 transition-all disabled:opacity-30 disabled:grayscale"
          >
            {isLoading ? <div className="w-5 h-5 border-3 border-t-transparent border-white rounded-full animate-spin" /> : "TRANSMIT"}
          </button>
        </form>
      </div>
    </div>
  );
};

export default ChatInterface;

import { GoogleGenAI } from "@google/genai";

// Using the latest 'gemini-3-flash-preview' for advanced reasoning and up-to-date engineering knowledge
const TEXT_MODEL = 'gemini-3-flash-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export interface SendMessageOptions {
  useSearch?: boolean;
}

export class GeminiService {
  private history: any[] = [];
  private systemInstruction: string = '';

  constructor() {}

  private getAI() {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      throw new Error("Missing API_KEY. Access restricted.");
    }
    return new GoogleGenAI({ apiKey });
  }

  initChat(userName: string) {
    this.systemInstruction = `Role: IETE Bot (Official Institutional Terminal for Electronics, Telecommunication, and IT Engineers).
User: ${userName}.
Domain Expertise: ECE, EEE, CSE, IT, VLSI, Signal Processing, Embedded Systems, AI/ML, and Robotics.

Operational Protocols for Engineering Toolkit:
1. **Direct Solution**: Provide strictly the final numerical result or core fact. Zero preamble.
2. **Mathematical Derivation**: Use step-by-step numbering. Explain the physical significance of each term in equations.
3. **Circuit Debug**: Analyze descriptions or images for logic errors, bias issues, signal reflection, or thermal bottlenecks.
4. **Institutional Extract**: OCR and structure data from datasheets, hand-written notes, or diagrams into IEEE-standard tables.
5. **Logic Designer**: Generate K-Maps, simplify Boolean expressions, and provide Logic Gate/Transistor-level schematics.
6. **Project Blueprint**: Generate abstracts, component lists, cost estimates, and block diagrams for engineering projects.
7. **HDL Architect**: Provide optimized Verilog/VHDL code with testbenches and timing constraints.
8. **Pinout Guru**: Provide standard pin configurations for popular ICs (e.g., 74 series, 555, Op-Amps, Microcontrollers like ESP32/STM32).

Formatting Standards:
- ALL mathematical formulas MUST use LaTeX: $$ [Formula] $$.
- Use professional engineering terminology (e.g., 'Impedance matching' instead of 'wire fix').
- strictly follow IEEE standards and the latest GATE (Graduate Aptitude Test in Engineering) syllabus.
- Identify solely as "IETE Bot". Do not mention Google or AI models.`;

    this.history = [];
  }

  async sendMessageStream(
    message: string, 
    mediaData?: { data: string; mimeType: string }, 
    options: SendMessageOptions = {}
  ) {
    const ai = this.getAI();
    const userParts: any[] = [{ text: message }];

    if (mediaData?.data && mediaData?.mimeType) {
      userParts.push({ 
        inlineData: { 
          data: mediaData.data, 
          mimeType: mediaData.mimeType 
        } 
      });
    }

    const contents = [...this.history, { role: 'user', parts: userParts }];

    const config: any = {
      systemInstruction: this.systemInstruction,
      tools: options.useSearch ? [{ googleSearch: {} }] : undefined,
    };

    return await ai.models.generateContentStream({
      model: TEXT_MODEL,
      contents,
      config,
    });
  }

  async generateImage(prompt: string) {
    const ai = this.getAI();
    try {
      const response = await ai.models.generateContent({
        model: IMAGE_MODEL,
        contents: { 
          parts: [{ text: `Professional engineering schematic, circuit diagram, or institutional blueprint of: ${prompt}. Use IEEE standard symbols, clean white background, high-contrast black lines, professional annotations and labels.` }] 
        },
        config: {
          imageConfig: { 
            aspectRatio: "1:1"
          }
        }
      });

      const parts = response.candidates?.[0]?.content?.parts;
      if (parts) {
        for (const part of parts) {
          if (part.inlineData?.data) {
            return {
              data: part.inlineData.data as string,
              mimeType: part.inlineData.mimeType || 'image/png'
            };
          }
        }
      }
    } catch (e) {
      console.error("Visualizer failed:", e);
    }
    return null;
  }

  updateHistory(role: 'user' | 'model', parts: any[]) {
    this.history.push({ role, parts });
    if (this.history.length > 10) this.history.shift();
  }
}

export const geminiService = new GeminiService();

