import React, { useState, useRef, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import remarkGfm from 'remark-gfm';
import { UserProfile, Message } from '../types';
import { geminiService } from '../geminiService';

interface ChatInterfaceProps { user: UserProfile; }

type ToolkitAction = 
  | 'extract' | 'debug' | 'visualize' | 'boolean' | 'gate_pyq' 
  | 'direct' | 'step_by_step' | 'viva' | 'pinout' | 'hdl' | 'project' | 'datasheet' | 'formula_ocr';

const ChatInterface: React.FC<ChatInterfaceProps> = ({ user }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [selectedMedia, setSelectedMedia] = useState<{ data: string; mimeType: string } | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const BOT_LOGO = "https://jit.ac.in/assets/uploads/2022/12/IETE-logo.png";

  useEffect(() => {
    const getGreeting = () => {
      const h = new Date().getHours();
      if (h < 12) return "Good morning";
      if (h < 17) return "Good afternoon";
      return "Good evening";
    };

    const initialId = 'init-' + Date.now();
    setMessages([{ id: initialId, role: 'assistant', content: '', timestamp: new Date() }]);
    geminiService.initChat(user.name);

    const timeGreeting = getGreeting();
    const welcome = `${timeGreeting}, ${user.name}. Institutional Neural Link initialized. I am IETE Bot. I've activated the **Extract & Derivation modules** for your session. How may I assist your engineering research today?`;
    let current = "";
    const words = welcome.split(" ");
    let i = 0;

    setIsTyping(true);
    const interval = setInterval(() => {
      if (i < words.length) {
        current += (i === 0 ? "" : " ") + words[i];
        setMessages(prev => prev.map(m => m.id === initialId ? { ...m, content: current } : m));
        i++;
      } else {
        clearInterval(interval);
        setIsTyping(false);
      }
    }, 20);

    return () => clearInterval(interval);
  }, [user.name]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isLoading, isTyping]);

  const handleActionClick = async (type: ToolkitAction) => {
    if (isLoading || isTyping) return;

    // Tools that prioritize visual data (Camera Trigger)
    if ((type === 'extract' || type === 'debug' || type === 'formula_ocr') && !selectedMedia) {
       fileInputRef.current?.click();
       return;
    }

    let promptSuffix = "";
    let context = input.trim();

    switch(type) {
      case 'formula_ocr':
        promptSuffix = "EXTRACT TEXT & FORMULA: Digitization required. Accurately transcribe all text and provide mathematical formulas in LaTeX ($$ ... $$) from the attached source.";
        break;
      case 'step_by_step': 
        promptSuffix = "STEP-BY-STEP SOLUTION: Provide a full modular derivation with stages for: " + context; 
        break;
      case 'direct': 
        promptSuffix = "DIRECT ANSWER: Final result only for: " + context; 
        break;
      case 'debug': 
        promptSuffix = "CIRCUIT DEBUG & ANALYSIS: Analyze flaws in: " + context; 
        break;
      case 'extract': 
        promptSuffix = "DATA EXTRACTION (Tabular): Extract technical parameters from: " + context; 
        break;
      case 'boolean': 
        promptSuffix = "BOOLEAN LOGIC & K-MAP: Simplify and show logic for: " + context; 
        break;
      case 'gate_pyq': 
        promptSuffix = "GATE PYQ RESEARCH: Find and solve related GATE question for: " + context; 
        break;
      case 'pinout':
        promptSuffix = "IC PINOUT: Functional pin description for: " + context;
        break;
      case 'hdl':
        promptSuffix = "HDL ARCHITECT: Verilog/VHDL optimized code for: " + context;
        break;
      case 'project':
        promptSuffix = "PROJECT BLUEPRINT: Comprehensive abstract and component list for: " + context;
        break;
      case 'datasheet':
        promptSuffix = "DATASHEET SUMMARY: Key electrical parameters for: " + context;
        break;
      case 'visualize':
        if (!context) {
          const topic = prompt("Enter Technical Topic to Visualize:");
          if (topic) await processVisualizer(topic);
          return;
        }
        await processVisualizer(context);
        return;
      default:
        promptSuffix = context;
    }

    // Fixed: Removed 'visualize' check as it is unreachable here due to the early return in switch.
    if (!context && !selectedMedia && type !== 'formula_ocr') {
       const userContext = prompt(`Enter ${type.toUpperCase().replace('_', ' ')} query:`) || "";
       if (!userContext) return;
       promptSuffix = promptSuffix.replace(context, userContext);
    }

    const useSearch = ['gate_pyq', 'datasheet', 'pinout'].includes(type);

    await processMessage(promptSuffix, selectedMedia || undefined, useSearch);
    setSelectedMedia(null);
    setInput('');
  };

  const processVisualizer = async (topic: string) => {
    setIsLoading(true);
    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, 
      { id: Date.now().toString(), role: 'user', content: `Requesting Schematic: ${topic}`, timestamp: new Date() },
      { id: assistantId, role: 'assistant', content: `Processing schematic for ${topic}...`, timestamp: new Date() }
    ]);

    try {
      const result = await geminiService.generateImage(topic);
      if (result) {
        setMessages(prev => prev.map((msg: Message): Message => msg.id === assistantId ? { 
          ...msg, content: `Institutional blueprint for **${topic}** rendered.`, 
          image: { data: result.data, mimeType: result.mimeType } 
        } : msg));
      }
    } catch (e: any) {
      setMessages(prev => prev.map((msg: Message): Message => msg.id === assistantId ? { ...msg, content: `Visualization Failure: ${e.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const processMessage = async (text: string, media?: { data: string; mimeType: string }, useSearch: boolean = false) => {
    if (isLoading || isTyping) return;
    setIsLoading(true);

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: text, timestamp: new Date(), image: media };
    setMessages(prev => [...prev, userMsg]);

    const assistantId = (Date.now() + 1).toString();
    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: '', timestamp: new Date() }]);

    try {
      let fullContent = '';
      const stream = await geminiService.sendMessageStream(text, media, { useSearch });

      for await (const chunk of stream) {
        fullContent += chunk.text || "";
        const grounding = chunk.candidates?.[0]?.groundingMetadata?.groundingChunks;
        const newSources = grounding?.map((c: any) => ({
          title: c.web?.title || 'Tech Source',
          uri: c.web?.uri || ''
        })).filter((s: any) => s.uri);

        setMessages(prev => prev.map((msg: Message): Message => 
          msg.id === assistantId ? { 
            ...msg, 
            content: fullContent,
            sources: newSources?.length ? [...(msg.sources || []), ...newSources] : msg.sources
          } : msg
        ));
      }
      geminiService.updateHistory('user', [{ text }, ...(media ? [{ inlineData: media }] : [])]);
      geminiService.updateHistory('model', [{ text: fullContent }]);
    } catch (error: any) {
      setMessages(prev => prev.map((msg: Message): Message => msg.id === assistantId ? { ...msg, content: `Transmission Link Error: ${error.message}` } : msg));
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && !selectedMedia) || isLoading || isTyping) return;
    const txt = input;
    const media = selectedMedia;
    setInput('');
    setSelectedMedia(null);
    processMessage(txt, media || undefined);
  };

  return (
    <div className="flex-1 flex flex-col theme-glass-card rounded-[2.5rem] overflow-hidden h-[calc(100vh-180px)] border-white/5">
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 chat-blueprint">
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[92%] md:max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className="w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center bg-white border border-black/10 shadow-lg overflow-hidden p-0.5">
                {msg.role === 'user' ? <span className="font-black text-blue-900 text-sm uppercase">{user.name[0]}</span> : <img src={BOT_LOGO} className="w-full h-full object-contain" alt="IETE" />}
              </div>
              <div className="flex flex-col gap-2">
                <div className={`rounded-3xl px-6 py-5 shadow-2xl border backdrop-blur-xl transition-all ${msg.role === 'user' ? 'bg-blue-950 text-white border-blue-800' : 'bg-[var(--card-bg)] text-[var(--text-primary)] border-[var(--border-color)]'}`}>
                  <div className="markdown-body prose prose-invert max-w-none text-[15px] leading-relaxed">
                    <ReactMarkdown remarkPlugins={[remarkMath, remarkGfm]} rehypePlugins={[rehypeKatex]}>{msg.content}</ReactMarkdown>
                    {msg.id.startsWith('init-') && isTyping && <span className="typing-cursor"></span>}
                  </div>
                  {msg.sources && msg.sources.length > 0 && (
                    <div className="mt-6 pt-4 border-t border-white/10 flex flex-wrap gap-2">
                      {msg.sources.map((s, i) => <a key={i} href={s.uri} target="_blank" rel="noopener noreferrer" className="text-[10px] bg-blue-500/10 px-3 py-1.5 rounded-full text-blue-400 font-black border border-blue-500/20 hover:bg-blue-500/30 transition-all uppercase tracking-widest">{s.title}</a>)}
                    </div>
                  )}
                </div>
                {msg.image && (
                  <div className="rounded-2xl border border-[var(--border-color)] overflow-hidden bg-white/5 p-1.5 shadow-2xl transform hover:scale-[1.01] transition-transform">
                    <img src={`data:${msg.image.mimeType};base64,${msg.image.data}`} className="w-full h-auto max-h-[600px] object-contain rounded-xl" alt="Technical Visualization" />
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Engineering Power Toolkit */}
      <div className="px-6 py-4 bg-black/40 border-t border-white/5 overflow-x-auto no-scrollbar shadow-inner">
        <div className="flex flex-col gap-4">
          <div className="flex items-center gap-4 overflow-x-auto no-scrollbar pb-1">
            <div className="flex items-center gap-2">
              <span className="text-[9px] font-black bg-blue-600 text-white px-2 py-0.5 rounded uppercase">Vision</span>
              <button onClick={() => handleActionClick('formula_ocr')} className="iete-tool-btn border-blue-500/50 bg-blue-500/10">📝 Extract Formula</button>
              <button onClick={() => handleActionClick('debug')} className="iete-tool-btn">🛠️ Debug Circuit</button>
              <button onClick={() => handleActionClick('visualize')} className="iete-tool-btn">🎨 Visualize</button>
            </div>
            <div className="flex items-center gap-2 border-l border-white/10 pl-3">
              <span className="text-[9px] font-black bg-emerald-600 text-white px-2 py-0.5 rounded uppercase">Logic</span>
              <button onClick={() => handleActionClick('step_by_step')} className="iete-tool-btn border-emerald-500/50 bg-emerald-500/10">🔢 Step-by-Step</button>
              <button onClick={() => handleActionClick('boolean')} className="iete-tool-btn">🧮 K-Map</button>
              <button onClick={() => handleActionClick('hdl')} className="iete-tool-btn">💻 HDL Architect</button>
            </div>
            <div className="flex items-center gap-2 border-l border-white/10 pl-3">
              <span className="text-[9px] font-black bg-rose-600 text-white px-2 py-0.5 rounded uppercase">Docs</span>
              <button onClick={() => handleActionClick('gate_pyq')} className="iete-tool-btn">🎓 GATE PYQ</button>
              <button onClick={() => handleActionClick('datasheet')} className="iete-tool-btn">📑 Datasheet</button>
              <button onClick={() => handleActionClick('pinout')} className="iete-tool-btn">📍 Pinout</button>
            </div>
          </div>
        </div>
      </div>

      <div className="p-4 md:p-8 bg-[var(--header-bg)] border-t border-[var(--border-color)]">
        {selectedMedia && (
          <div className="mb-6 flex items-center gap-4 p-4 bg-blue-900/10 rounded-3xl border border-blue-900/30 animate-in slide-in-from-bottom-2">
            <div className="relative group">
              <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-20 w-20 rounded-2xl object-cover border-2 border-blue-500 shadow-2xl" />
              <button onClick={() => setSelectedMedia(null)} className="absolute -top-3 -right-3 bg-red-600 text-white rounded-full p-2 shadow-xl hover:bg-red-700 transition-all">
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            </div>
            <div className="flex flex-col">
              <h4 className="text-[11px] font-black text-blue-400 uppercase tracking-widest">Vision Data Loaded</h4>
              <p className="text-[10px] text-[var(--text-secondary)]">Ready for Text/Formula extraction or Debugging.</p>
            </div>
          </div>
        )}

        <form onSubmit={handleSend} className="flex gap-4 max-w-7xl mx-auto">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
            const file = e.target.files?.[0];
            if (file) {
              const reader = new FileReader();
              reader.onloadend = () => {
                const b64 = (reader.result as string).split(',')[1];
                setSelectedMedia({ data: b64, mimeType: file.type });
              };
              reader.readAsDataURL(file);
            }
          }} />
          <button 
            type="button" 
            onClick={() => fileInputRef.current?.click()} 
            className="p-5 rounded-3xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-secondary)] hover:text-blue-500 hover:border-blue-500/30 transition-all shadow-inner group"
          >
            <svg className="w-6 h-6 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>
          <input
            type="text" value={input} onChange={(e) => setInput(e.target.value)}
            placeholder="Ask engineering query or use Power Tools..."
            className="flex-1 px-8 py-5 rounded-3xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-primary)] outline-none focus:border-blue-900/50 text-sm transition-all shadow-inner placeholder:text-white/20"
            disabled={isLoading || isTyping}
