    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const b64 = (reader.result as string).split(',')[1];
        setSelectedMedia({ data: b64, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
    e.target.value = '';
  };

