            </button>
            <button onClick={() => { fileInputRef.current?.click(); setShowUploadOptions(false); }} className="flex items-center gap-3 px-4 py-3 hover:bg-emerald-500/10 rounded-xl text-[10px] font-black text-emerald-400 uppercase transition-all group">
              <div className="bg-emerald-500/20 p-2 rounded-lg"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg></div>
              Select File
            </button>
          </div>
        )}

        {selectedMedia && (
          <div className="mb-4 flex items-center gap-3 p-3 bg-blue-900/20 rounded-xl border border-blue-500/30">
            <div className="relative">
              <img src={`data:${selectedMedia.mimeType};base64,${selectedMedia.data}`} className="h-14 w-14 rounded-lg object-cover border border-blue-500" />
              <button onClick={() => setSelectedMedia(null)} className="absolute -top-2 -right-2 bg-red-600 text-white rounded-full p-1 shadow-lg"><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"></path></svg></button>
            </div>
            <div className="flex flex-col"><p className="text-[9px] font-black text-blue-400 uppercase">Vision Feed Linked</p><p className="text-[8px] opacity-60">Ready for diagnostic/analysis.</p></div>
