      <div className="px-3 md:px-6 py-3 bg-black/60 border-t border-white/5 overflow-x-auto no-scrollbar">
        <div className="flex flex-col gap-3">
          {/* Action Row - Top: Search Toggle */}
          <div className="flex items-center gap-2 pb-1 border-b border-white/5">
            <button onClick={() => setDeepSearch(!deepSearch)} className={`iete-tool-btn min-w-[120px] ${deepSearch ? 'bg-blue-500/40 border-blue-400 text-blue-300' : 'opacity-60'}`}>
              {deepSearch ? '⚡ SEARCH ACTIVE' : '🌐 SEARCH OFF'}
            </button>
            <div className="h-4 w-px bg-white/10 mx-1"></div>
            <p className="text-[8px] font-black text-white/30 uppercase tracking-widest whitespace-nowrap">Specialized Toolsets:</p>
