              <div key={cat.name} className="flex flex-col gap-1.5 min-w-max">
                <span className="text-[7px] font-black text-blue-500/60 uppercase tracking-tighter px-1">{cat.name}</span>
                <div className="flex items-center gap-1.5">
                  {cat.tools.map((tool) => (
                    <button 
                      key={tool} 
                      onClick={() => handleActionClick(tool)} 
