        <form onSubmit={handleSend} className="flex gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
          <input type="file" ref={cameraInputRef} className="hidden" accept="image/*" capture="environment" onChange={handleFileChange} />

          <button type="button" onClick={() => setShowUploadOptions(!showUploadOptions)} className={`p-3 md:p-4 rounded-xl md:rounded-2xl bg-[var(--input-bg)] border border-[var(--border-color)] text-[var(--text-secondary)] transition-all ${showUploadOptions ? 'text-blue-500 ring-2 ring-blue-500/30' : 'hover:text-blue-500'}`}>
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>

          <input
            type="text" value={input} onChange={(e) => setInput(e.target.value)}
            placeholder={activeAction ? `Active Mode: ${getActionLabel(activeAction)}...` : "Transmit engineering query..."}
            className={`flex-1 px-4 md:px-5 py-3 md:py-4 rounded-xl md:rounded-2xl bg-[var(--input-bg)] border transition-all shadow-inner text-xs outline-none ${activeAction ? 'border-blue-500/50 ring-2 ring-blue-500/10' : 'border-[var(--border-color)] focus:border-blue-900/50'}`}
            disabled={isLoading}
          />
          <button type="submit" disabled={isLoading || isTyping || (!input.trim() && !selectedMedia && !activeAction)} className="px-5 md:px-8 py-3 md:py-4 bg-gradient-to-br from-blue-700 to-blue-900 text-white rounded-xl md:rounded-2xl font-black uppercase text-[10px] md:text-[11px] tracking-widest shadow-xl disabled:opacity-30 transition-all active:scale-95">
            {isLoading ? <div className="w-4 h-4 border-2 border-t-transparent border-white rounded-full animate-spin" /> : "EXECUTE"}
          </button>
        </form>
      </div>

      <style>{`
        .iete-tool-btn {
          display: flex;
          align-items: center;
          gap: 0.3rem;
          padding: 0.4rem 0.6rem;
          border-radius: 0.6rem;
          background: rgba(255, 255, 255, 0.04);
          border: 1px solid rgba(255, 255, 255, 0.08);
          color: rgba(255, 255, 255, 0.7);
          font-size: 8px;
          font-weight: 700;
          text-transform: uppercase;
          white-space: nowrap;
          transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
        }
        .iete-tool-btn:hover { background: rgba(59, 130, 246, 0.12); border-color: rgba(59, 130, 246, 0.4); color: white; transform: translateY(-1px); }
        .iete-tool-active { background: rgba(59, 130, 246, 0.25) !important; border-color: #3b82f6 !important; color: #fff !important; box-shadow: 0 0 15px rgba(59, 130, 246, 0.4); }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

